export const getOrders = (): Order[] => {
  if (!db) return [];
  try {
      const stmt = db.prepare("SELECT * FROM orders ORDER BY timestamp DESC");
      const orders: Order[] = [];

      while (stmt.step()) {
        const row = stmt.getAsObject();

        const itemsStmt = db.prepare("SELECT * FROM order_items WHERE order_id = ?");
        itemsStmt.bind([row.id]);
        const items: CartItem[] = [];
        while (itemsStmt.step()) {
          const itemRow = itemsStmt.getAsObject();
          items.push({
            id: itemRow.id.toString(), // Attention ici, modification potentielle pour lier au vrai ID produit
            name: itemRow.name,
            price: itemRow.price,
            costPrice: 0, // Information non stockée dans order_items pour l'instant
            stock: 0,
            quantity: itemRow.quantity,
            category: 'Food' as any 
          });
        }
        itemsStmt.free();

        orders.push({
          id: row.id,
          total: row.total,
          status: row.status as OrderStatus,
          timestamp: row.timestamp,
          tableNumber: row.table_number,
          tableName: row.table_name || (row.table_number ? row.table_number.toString() : '?'),
          clientId: row.client_id,
          clientName: row.client_name,
          paymentMethod: row.payment_method as PaymentMethod,
          items: items
        });
      }
      stmt.free();
      return orders;
  } catch (e) {
      return [];
  }
};

export const insertOrder = (order: Order) => {
  if (!db) return;

  // 1. Insert Order
  db.run("INSERT INTO orders (id, total, status, timestamp, table_number, table_name, client_id, client_name, payment_method) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)", [
    order.id, 
    order.total, 
    order.status, 
    order.timestamp, 
    order.tableNumber || 0,
    order.tableName || (order.tableNumber ? order.tableNumber.toString() : 'Unknown'),
    order.clientId || null,
    order.clientName || null,
    order.paymentMethod || null
  ]);

  // 2. Insert Items and Decrement Stock
  const stmt = db.prepare("INSERT INTO order_items (order_id, name, price, quantity) VALUES (?, ?, ?, ?)");
  const stockStmt = db.prepare("UPDATE products SET stock = stock - ? WHERE name = ?"); // Utilisation du Nom faute d'ID fiable dans le CartItem actuel, idéalement utiliser ID

  order.items.forEach(item => {
    stmt.run([order.id, item.name, item.price, item.quantity]);

    // Décrémentation du stock
    // Note: Dans une app réelle, on utiliserait l'ID produit. Ici on utilise le nom car CartItem hérite parfois mal
    try {
        stockStmt.run([item.quantity, item.name]);
    } catch(e) {
        console.error("Stock update failed for", item.name);
    }
  });

  stmt.free();
  stockStmt.free();

  saveDB();
};

export const updateOrderStatusInDB = (orderId: string, status: OrderStatus) => {
  if (!db) return;
  db.run("UPDATE orders SET status = ? WHERE id = ?", [status, orderId]);
  saveDB();
};

export const processOrderPayment = (orderId: string, method: PaymentMethod, total: number, clientId?: string) => {
    if (!db) return;

    db.run("UPDATE orders SET status = ?, payment_method = ? WHERE id = ?", [OrderStatus.PAID, method, orderId]);

    if (clientId) {
        let sql = `
            UPDATE clients 
            SET total_spent = total_spent + ?, 
                loyalty_points = loyalty_points + ?,
                last_visit = ?
        `;
        const pointsEarned = Math.floor(total / 10);
        const params: any[] = [total, pointsEarned, Date.now()];

        if (method === PaymentMethod.TAB) {
            sql += `, balance = balance - ?`;
            params.push(total);
        }

        sql += ` WHERE id = ?`;
        params.push(clientId);

        db.run(sql, params);
    }

    saveDB();
};

import { Product, Order, OrderStatus, CartItem, CategoryDef, Category, TableDef, Client, PaymentMethod } from '../types';
import { INITIAL_MENU } from '../constants';

let db: any = null;
const DB_STORAGE_KEY = 'barflow_sqlite_db_v1';

// Initialisation de la base de données
export const initDB = async () => {
  if (db) return;

  // Ensure initSqlJs is available
  if (typeof (window as any).initSqlJs !== 'function') {
      console.error("initSqlJs is not a function. Waiting or checking script load.");
      // Simple retry mechanism or failure
      throw new Error("sql.js library not loaded properly.");
  }

  // Configuration de sql.js pour charger le fichier wasm depuis le CDN
  // Utilisation de la version 1.8.0 qui est très stable
  const SQL = await (window as any).initSqlJs({
    locateFile: (file: string) => `https://cdnjs.cloudflare.com/ajax/libs/sql.js/1.8.0/${file}`
  });

  // Tentative de chargement depuis le localStorage
  const savedDb = localStorage.getItem(DB_STORAGE_KEY);

  if (savedDb) {
    try {
        const binaryString = atob(savedDb);
        const bytes = new Uint8Array(binaryString.length);
        for (let i = 0; i < binaryString.length; i++) {
        bytes[i] = binaryString.charCodeAt(i);
        }
        db = new SQL.Database(bytes);
    } catch (e) {
        console.error("Failed to load saved DB, creating new one", e);
        db = new SQL.Database();
    }
  } else {
    db = new SQL.Database();
  }

  // Création des tables et Migrations
  createTables();
  applyMigrations(); 

  if (!savedDb) {
      seedData();
      saveDB();
  }
};

// Sauvegarde de la DB dans le localStorage
const saveDB = () => {
  if (!db) return;
  const data = db.export();
  let binaryString = '';
  for (let i = 0; i < data.length; i++) {
    binaryString += String.fromCharCode(data[i]);
  }
  localStorage.setItem(DB_STORAGE_KEY, btoa(binaryString));
};

