export const getProducts = (): Product[] => {
  if (!db) return [];
  const stmt = db.prepare("SELECT * FROM products");
  const products: Product[] = [];
  while (stmt.step()) {
    const row = stmt.getAsObject();
    products.push({
      id: row.id, name: row.name, price: row.price, costPrice: row.cost_price || 0,
      stock: row.stock || 0, alertThreshold: row.alert_threshold || 5, 
      category: row.category, image: row.image, description: row.description,
      isAvailable: row.is_available === 1
    });
  }
  stmt.free();
  return products;
};

export const addProduct = (product: Product) => {
  if (!db) return;
  db.run("INSERT INTO products (id, name, price, cost_price, stock, alert_threshold, category, image, description, is_available) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)", [
    product.id, product.name, product.price, product.costPrice || 0, product.stock || 0, 
    product.alertThreshold || 5, product.category, product.image || '', product.description || '', product.isAvailable ? 1 : 0
  ]);
  saveDB();
};

export const updateProduct = (product: Product) => {
  if (!db) return;
  db.run("UPDATE products SET name = ?, price = ?, cost_price = ?, stock = ?, alert_threshold = ?, category = ?, image = ?, description = ?, is_available = ? WHERE id = ?", [
    product.name, product.price, product.costPrice, product.stock, product.alertThreshold, 
    product.category, product.image, product.description, product.isAvailable ? 1 : 0, product.id
  ]);
  saveDB();
};

export const replenishStock = (productId: string, quantity: number, note: string) => {
    if (!db) return;
    db.run("UPDATE products SET stock = stock + ? WHERE id = ?", [quantity, productId]);
    db.run("INSERT INTO stock_history (product_id, quantity, timestamp, note) VALUES (?, ?, ?, ?)", [
        productId, quantity, Date.now(), note
    ]);
    saveDB();
};

export const getStockHistory = (productId: string): StockEntry[] => {
    if (!db) return [];
    const stmt = db.prepare("SELECT * FROM stock_history WHERE product_id = ? ORDER BY timestamp DESC");
    stmt.bind([productId]);
    const entries: StockEntry[] = [];
    while (stmt.step()) {
        const row = stmt.getAsObject();
        entries.push({
            id: row.id, productId: row.product_id, quantity: row.quantity, 
            timestamp: row.timestamp, note: row.note
        });
    }
    stmt.free();
    return entries;
};

export const deleteProduct = (id: string) => {
  if (!db) return;
  db.run("DELETE FROM products WHERE id = ?", [id]);
  saveDB();
};

export const getOrders = (): Order[] => {
  if (!db) return [];
  try {
      const stmt = db.prepare("SELECT * FROM orders ORDER BY timestamp DESC");
      const orders: Order[] = [];
      while (stmt.step()) {
        const row = stmt.getAsObject();
        const itemsStmt = db.prepare("SELECT * FROM order_items WHERE order_id = ?");
        itemsStmt.bind([row.id]);
        const items: CartItem[] = [];
        while (itemsStmt.step()) {
          const itemRow = itemsStmt.getAsObject();
          items.push({ id: itemRow.id.toString(), name: itemRow.name, price: itemRow.price, costPrice: 0, stock: 0, alertThreshold: 0, quantity: itemRow.quantity, category: 'Food' as any });
        }
        itemsStmt.free();
        orders.push({
          id: row.id, total: row.total, status: row.status as OrderStatus, timestamp: row.timestamp,
          tableNumber: row.table_number, tableName: row.table_name || '?', clientId: row.client_id,
          clientName: row.client_name, paymentMethod: row.payment_method as PaymentMethod, items: items
        });
      }
      stmt.free();
      return orders;
  } catch (e) { return []; }
};

export const insertOrder = (order: Order) => {
  if (!db) return;
  db.run("INSERT INTO orders (id, total, status, timestamp, table_number, table_name, client_id, client_name, payment_method) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)", [
    order.id, order.total, order.status, order.timestamp, order.tableNumber || 0, order.tableName || 'Unknown', order.clientId || null, order.clientName || null, order.paymentMethod || null
  ]);
  const stmt = db.prepare("INSERT INTO order_items (order_id, name, price, quantity) VALUES (?, ?, ?, ?)");
  const stockStmt = db.prepare("UPDATE products SET stock = stock - ? WHERE name = ?");
  order.items.forEach(item => {
    stmt.run([order.id, item.name, item.price, item.quantity]);
    try { stockStmt.run([item.quantity, item.name]); } catch(e) {}
  });
  stmt.free();
  stockStmt.free();
  saveDB();
};

export const updateOrderStatusInDB = (orderId: string, status: OrderStatus) => {
  if (!db) return;
  db.run("UPDATE orders SET status = ? WHERE id = ?", [status, orderId]);
  saveDB();
};

export const processOrderPayment = (orderId: string, method: PaymentMethod, total: number, clientId?: string) => {
    if (!db) return;
    db.run("UPDATE orders SET status = ?, payment_method = ? WHERE id = ?", [OrderStatus.PAID, method, orderId]);
    if (clientId) {
        let sql = `UPDATE clients SET total_spent = total_spent + ?, loyalty_points = loyalty_points + ?, last_visit = ?`;
        const pointsEarned = Math.floor(total / 10);
        const params: any[] = [total, pointsEarned, Date.now()];
        if (method === PaymentMethod.TAB) {
            sql += `, balance = balance - ?`;
            params.push(total);
        }
        sql += ` WHERE id = ?`;
        params.push(clientId);
        db.run(sql, params);
    }
    saveDB();
};

import React, { useState, useMemo, useEffect } from 'react';
import { Product, CategoryDef, StockEntry } from '../types';
import { addProduct, deleteProduct, updateProduct, replenishStock, getStockHistory } from '../services/db';
import { Plus, Trash2, Search, Package, X, Edit2, LayoutGrid, List, CheckCircle, XCircle, Image as ImageIcon, TrendingUp, AlertTriangle, Layers, ArrowUp, History } from 'lucide-react';
import { getIconComponent } from '../components/IconRegistry';

interface ProductsPageProps {
  products: Product[];
  categories: CategoryDef[];
  refreshData: () => void;
  currency: string;
}

export const Products: React.FC<ProductsPageProps> = ({ products, categories, refreshData, currency }) => {
  // View State
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategoryFilter, setSelectedCategoryFilter] = useState('All');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [isRestockOpen, setIsRestockOpen] = useState(false);
  const [restockProduct, setRestockProduct] = useState<Product | null>(null);
  const [stockHistory, setStockHistory] = useState<StockEntry[]>([]);

  // Form State
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [costPrice, setCostPrice] = useState('');
  const [stock, setStock] = useState('');
  const [alertThreshold, setAlertThreshold] = useState(''); // Nouveau
  const [category, setCategory] = useState('');
  const [description, setDescription] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [isAvailable, setIsAvailable] = useState(true);

  // Restock Form
  const [restockQty, setRestockQty] = useState('');
  const [restockNote, setRestockNote] = useState('');

  // --- ACTIONS ---

  const handleOpenModal = (product?: Product) => {
    if (product) {
        setEditingProduct(product);
        setName(product.name);
        setPrice(product.price.toString());
        setCostPrice(product.costPrice?.toString() || '0');
        setStock(product.stock?.toString() || '0');
        setAlertThreshold(product.alertThreshold?.toString() || '5');
        setCategory(product.category);
        setDescription(product.description || '');
        setImageUrl(product.image || '');
        setIsAvailable(product.isAvailable !== undefined ? product.isAvailable : true);
    } else {
        setEditingProduct(null);
        setName('');
        setPrice('');
        setCostPrice('');
        setStock('');
        setAlertThreshold('5');
        setCategory(categories.length > 0 ? categories[0].name : '');
        setDescription('');
        setImageUrl('');
        setIsAvailable(true);
    }
    setIsModalOpen(true);
  };

  const handleOpenRestock = (product: Product) => {
      setRestockProduct(product);
      setRestockQty('');
      setRestockNote('');
      setStockHistory(getStockHistory(product.id));
      setIsRestockOpen(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !price) return;

    const catToUse = category || (categories.length > 0 ? categories[0].name : 'Divers');
    const imageToUse = imageUrl || `https://picsum.photos/200/200?random=${Date.now()}`;
    const stockVal = parseInt(stock) || 0;
    const thresholdVal = parseInt(alertThreshold) || 5;
    const costVal = parseFloat(costPrice) || 0;
    const priceVal = parseFloat(price);

    if (editingProduct) {
        const updated: Product = {
            ...editingProduct,
            name,
            price: priceVal,
            costPrice: costVal,
            stock: stockVal,
            alertThreshold: thresholdVal,
            category: catToUse,
            description,
            image: imageToUse,
            isAvailable
        };
        updateProduct(updated);
    } else {
        const newProduct: Product = {
            id: Math.random().toString(36).substr(2, 9),
            name,
            price: priceVal,
            costPrice: costVal,
            stock: stockVal,
            alertThreshold: thresholdVal,
            category: catToUse,
            description,
            image: imageToUse,
            isAvailable
        };
        addProduct(newProduct);
    }

    refreshData();
    setIsModalOpen(false);
  };

  const handleRestockSave = (e: React.FormEvent) => {
      e.preventDefault();
      if (!restockProduct || !restockQty) return;
      const qty = parseInt(restockQty);
      if (isNaN(qty) || qty === 0) return;

      replenishStock(restockProduct.id, qty, restockNote || 'Réapprovisionnement manuel');
      refreshData();
      setIsRestockOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Êtes-vous sûr de vouloir supprimer ce produit ?')) {
      deleteProduct(id);
      refreshData();
    }
  };

  const handleToggleAvailability = (product: Product, e: React.MouseEvent) => {
      e.stopPropagation();
      const updated = { ...product, isAvailable: !product.isAvailable };
      updateProduct(updated);
      refreshData();
  };

  // --- CALCULATIONS ---
  const calculateMargin = () => {
      const p = parseFloat(price) || 0;
      const c = parseFloat(costPrice) || 0;
      if (p === 0) return { value: 0, percent: 0 };
      const margin = p - c;
      const percent = (margin / p) * 100;
      return { value: margin, percent };
  };
  const marginStats = calculateMargin();

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
        const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                              p.category.toLowerCase().includes(searchQuery.toLowerCase());
        const matchesCategory = selectedCategoryFilter === 'All' || p.category === selectedCategoryFilter;
        return matchesSearch && matchesCategory;
    });
  }, [products, searchQuery, selectedCategoryFilter]);

  const getCategoryIcon = (catName: string) => {
    const cat = categories.find(c => c.name === catName);
    return cat ? cat.icon : 'Shapes';
  };

  const getStockStatus = (product: Product) => {
      if (product.stock <= 0) return { label: 'Rupture', color: 'text-red-500 bg-red-500/10 border-red-500/30', alert: true };
      if (product.stock <= product.alertThreshold) return { label: 'Stock Faible', color: 'text-orange-500 bg-orange-500/10 border-orange-500/30', alert: true };
      return { label: 'En Stock', color: 'text-green-500 bg-green-500/10 border-green-500/20', alert: false };
  };

  return (
    <div className="p-4 md:p-8 h-full overflow-y-auto bg-slate-950 flex flex-col">
      {/* HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4 shrink-0">
        <div>
          <h1 className="text-3xl font-bold text-white flex items-center gap-3">
            <Package className="text-bar-accent" />
            Inventaire & Produits
          </h1>
          <p className="text-slate-400 mt-1">Gestion des prix, stocks et alertes critiques</p>
        </div>

        <button 
          onClick={() => handleOpenModal()}
          className="bg-bar-accent hover:bg-pink-600 text-white font-bold py-3 px-6 rounded-xl flex items-center gap-2 transition-colors shadow-lg shadow-bar-accent/25"
        >
          <Plus size={20} />
          Nouveau Produit
        </button>
      </div>

      {/* CONTROLS BAR */}
      <div className="bg-slate-900 border border-slate-800 rounded-xl p-3 mb-6 flex flex-col md:flex-row gap-3 items-center sticky top-0 z-10 shadow-md">
          <div className="relative flex-1 w-full">
             <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
             <input 
               type="text" 
               placeholder="Rechercher..." 
               className="w-full bg-slate-950 border border-slate-800 rounded-lg py-2 pl-10 pr-4 text-white focus:ring-2 focus:ring-bar-accent outline-none"
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
             />
          </div>

          <div className="w-full md:w-auto">
             <select 
               value={selectedCategoryFilter}
               onChange={(e) => setSelectedCategoryFilter(e.target.value)}
               className="w-full bg-slate-950 border border-slate-800 rounded-lg py-2 px-4 text-white outline-none focus:border-bar-accent cursor-pointer"
             >
                <option value="All">Toutes catégories</option>
                {categories.map(cat => (
                    <option key={cat.id} value={cat.name}>{cat.name}</option>
                ))}
             </select>
          </div>

          <div className="flex bg-slate-950 rounded-lg p-1 border border-slate-800">
             <button 
               onClick={() => setViewMode('grid')}
               className={`p-2 rounded-md transition-colors ${viewMode === 'grid' ? 'bg-slate-800 text-bar-accent' : 'text-slate-400 hover:text-white'}`}
               title="Vue Grille"
             >
               <LayoutGrid size={18} />
             </button>
             <button 
               onClick={() => setViewMode('list')}
               className={`p-2 rounded-md transition-colors ${viewMode === 'list' ? 'bg-slate-800 text-bar-accent' : 'text-slate-400 hover:text-white'}`}
               title="Vue Liste"
             >
               <List size={18} />
             </button>
          </div>
      </div>

      {/* PRODUCTS LIST/GRID */}
      <div className="flex-1 pb-24 md:pb-0">
        {viewMode === 'grid' ? (
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredProducts.map(product => {
                    const Icon = getIconComponent(getCategoryIcon(product.category));
                    const status = getStockStatus(product);
                    const margin = product.price - (product.costPrice || 0);
                    return (
                        <div key={product.id} className={`bg-slate-900 border rounded-xl overflow-hidden shadow-lg group flex flex-col h-full transition-all ${product.isAvailable === false ? 'border-red-900/50 opacity-80 grayscale-[0.5]' : 'border-slate-800 hover:border-slate-600'}`}>
                            <div className="relative h-44 w-full overflow-hidden bg-gradient-to-br from-slate-800 to-slate-700 flex items-center justify-center">
                                <Icon className="text-bar-accent w-16 h-16 drop-shadow-lg transform group-hover:scale-110 transition-transform duration-300" />
                                <div className="absolute top-2 right-2 flex flex-col gap-2 items-end">
                                     <span className={`text-[10px] font-bold px-2 py-1 rounded shadow-sm border flex items-center gap-1 backdrop-blur-md ${status.color} ${status.alert ? 'animate-pulse' : ''}`}>
                                         {status.alert && <AlertTriangle size={12} />}
                                         {status.label}: {product.stock}
                                     </span>
                                     <span className="bg-black/60 backdrop-blur-sm text-white text-[10px] px-2 py-1 rounded border border-white/10 uppercase tracking-tight">
                                         {product.category}
                                     </span>
                                </div>
                            </div>
                            <div className="p-4 flex-1 flex flex-col">
                                <div className="flex justify-between items-start mb-2">
                                    <h3 className="font-bold text-white text-base leading-tight line-clamp-2">{product.name}</h3>
                                    <div className="flex flex-col items-end">
                                        <span className="font-bold text-bar-accent whitespace-nowrap bg-slate-950 px-2 py-0.5 rounded border border-slate-800 text-sm">{product.price}{currency}</span>
                                    </div>
                                </div>

                                <div className="grid grid-cols-4 gap-2 mt-auto pt-4">
                                    <button 
                                      onClick={() => handleOpenRestock(product)}
                                      className="col-span-1 py-2 bg-green-500/10 hover:bg-green-500 text-green-500 hover:text-white rounded-lg transition-colors flex items-center justify-center border border-green-500/30"
                                      title="Réapprovisionner"
                                    >
                                        <ArrowUp size={18} />
                                    </button>
                                    <button 
                                      onClick={() => handleOpenModal(product)}
                                      className="col-span-1 py-2 bg-slate-800 hover:bg-blue-600 hover:text-white text-slate-300 rounded-lg transition-colors flex items-center justify-center border border-slate-700"
