        ) : (
             <div className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden shadow-lg overflow-x-auto">
                <table className="w-full text-left border-collapse">
                    <thead className="bg-slate-800/50 text-slate-400 text-xs uppercase font-medium">
                        <tr>
                            <th className="p-4 w-12">Dispo</th>
                            <th className="p-4">Produit</th>
                            <th className="p-4 hidden md:table-cell">Catégorie</th>
                            <th className="p-4 text-center">Stock</th>
                            <th className="p-4 text-center">Alerte</th>
                            <th className="p-4 text-right">Vente</th>
                            <th className="p-4 text-center">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-800">
                        {filteredProducts.map(product => {
                            const status = getStockStatus(product);
                            return (
                                <tr key={product.id} className="hover:bg-slate-800/30 transition-colors group">
                                    <td className="p-4">
                                        <button 
                                        onClick={(e) => handleToggleAvailability(product, e)}
                                        className={`w-8 h-8 rounded-full flex items-center justify-center transition-all ${product.isAvailable !== false ? 'bg-green-500/10 text-green-500' : 'bg-red-500/10 text-red-500'}`}
                                        >
                                            {product.isAvailable !== false ? <CheckCircle size={16} /> : <XCircle size={16} />}
                                        </button>
                                    </td>
                                    <td className="p-4">
                                        <div className="font-bold text-white text-base">{product.name}</div>
                                    </td>
                                    <td className="p-4 hidden md:table-cell">
                                        <span className="text-xs text-slate-400">{product.category}</span>
                                    </td>
                                    <td className="p-4 text-center">
                                        <span className={`px-2 py-1 rounded font-bold text-xs border ${status.color} ${status.alert ? 'animate-pulse' : ''}`}>
                                            {product.stock}
                                        </span>
                                    </td>
                                    <td className="p-4 text-center text-slate-500 text-xs">
                                        {product.alertThreshold}
                                    </td>
                                    <td className="p-4 text-right font-bold text-white">
                                        {product.price.toFixed(2)}{currency}
                                    </td>
                                    <td className="p-4">
                                        <div className="flex justify-center gap-2">
                                            <button onClick={() => handleOpenRestock(product)} className="p-2 bg-slate-800 hover:bg-green-600 text-green-500 hover:text-white rounded-lg transition-colors border border-slate-700"><ArrowUp size={16} /></button>
                                            <button onClick={() => handleOpenModal(product)} className="p-2 bg-slate-800 hover:bg-blue-600 hover:text-white text-slate-400 rounded-lg transition-colors border border-slate-700"><Edit2 size={16} /></button>
                                            <button onClick={() => handleDelete(product.id)} className="p-2 bg-slate-800 hover:bg-red-600 hover:text-white text-slate-400 rounded-lg transition-colors border border-slate-700"><Trash2 size={16} /></button>
                                        </div>
                                    </td>
                                </tr>
                            );
                        })}
                    </tbody>
                </table>
             </div>
        )}
      </div>

      {/* RE-STOCK MODAL */}
      {isRestockOpen && restockProduct && (
          <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/90 backdrop-blur-sm p-4 animate-in fade-in duration-200">
              <div className="bg-slate-900 border border-slate-800 w-full max-w-2xl rounded-2xl shadow-2xl overflow-hidden flex flex-col md:flex-row max-h-[90vh]">
                  {/* Form Side */}
                  <div className="flex-1 p-6 border-b md:border-b-0 md:border-r border-slate-800">
                      <div className="flex justify-between items-center mb-6">
                        <h2 className="text-xl font-bold text-white">Approvisionnement</h2>
                        <button onClick={() => setIsRestockOpen(false)} className="md:hidden text-slate-400 hover:text-white"><X size={24} /></button>
                      </div>

                      <div className="bg-slate-800/50 p-4 rounded-xl mb-6 border border-slate-700">
                          <p className="text-xs text-slate-500 uppercase font-bold mb-1">Produit</p>
                          <p className="text-lg font-bold text-white">{restockProduct.name}</p>
                          <div className="flex justify-between items-center mt-2">
                              <span className="text-sm text-slate-400">Stock actuel:</span>
                              <span className="bg-slate-950 px-3 py-1 rounded-full font-bold text-white">{restockProduct.stock}</span>
                          </div>
                      </div>

                      <form onSubmit={handleRestockSave} className="space-y-4">
                          <div>
                              <label className="block text-slate-400 text-sm font-medium mb-1">Quantité à ajouter</label>
                              <input 
                                type="number" 
                                required
                                value={restockQty}
                                onChange={e => setRestockQty(e.target.value)}
                                className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white font-bold text-xl focus:border-green-500 outline-none"
                                placeholder="0"
                                autoFocus
                              />
                          </div>
                          <div>
                              <label className="block text-slate-400 text-sm font-medium mb-1">Note (Fournisseur, n° facture...)</label>
                              <input 
                                type="text" 
                                value={restockNote}
                                onChange={e => setRestockNote(e.target.value)}
                                className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white text-sm focus:border-bar-accent outline-none"
                                placeholder="Livraison hebdo..."
                              />
                          </div>
                          <button type="submit" className="w-full py-4 bg-green-600 hover:bg-green-500 text-white font-bold rounded-xl shadow-lg shadow-green-900/20 flex items-center justify-center gap-2 mt-4">
                              <ArrowUp size={20} />
                              Valider l'entrée en stock
                          </button>
                      </form>
                  </div>

                  {/* History Side */}
                  <div className="w-full md:w-80 bg-slate-950/50 p-6 flex flex-col h-full overflow-hidden">
                      <div className="flex items-center justify-between mb-4">
                        <h3 className="text-sm font-bold text-slate-400 uppercase tracking-widest flex items-center gap-2">
                            <History size={16} /> Historique
                        </h3>
                        <button onClick={() => setIsRestockOpen(false)} className="hidden md:block text-slate-500 hover:text-white"><X size={20} /></button>
                      </div>

                      <div className="flex-1 overflow-y-auto pr-2 space-y-3 custom-scrollbar">
                          {stockHistory.length === 0 ? (
                              <div className="text-center py-10 text-slate-600 text-sm italic">Aucun historique d'approvisionnement.</div>
                          ) : (
                              stockHistory.map(entry => (
                                  <div key={entry.id} className="bg-slate-900 border border-slate-800 p-3 rounded-lg">
                                      <div className="flex justify-between items-start mb-1">
                                          <span className="text-green-500 font-bold">+{entry.quantity}</span>
                                          <span className="text-[10px] text-slate-600">{new Date(entry.timestamp).toLocaleDateString()}</span>
                                      </div>
                                      <p className="text-[11px] text-slate-400 line-clamp-2 leading-tight">{entry.note}</p>
                                  </div>
                              ))
                          )}
                      </div>
                  </div>
              </div>
          </div>
      )}

      {/* ADD/EDIT MODAL */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200 overflow-y-auto">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-lg rounded-2xl shadow-2xl p-6 relative my-8">
            <button 
              onClick={() => setIsModalOpen(false)}
              className="absolute top-4 right-4 text-slate-400 hover:text-white"
            >
              <X size={24} />
            </button>

            <h2 className="text-2xl font-bold text-white mb-6">
                {editingProduct ? 'Modifier le Produit' : 'Ajouter un Produit'}
            </h2>

            <form onSubmit={handleSave} className="space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <div className="md:col-span-2">
                    <label className="block text-slate-400 text-sm font-medium mb-1">Nom du produit</label>
                    <input type="text" required value={name} onChange={e => setName(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-bar-accent outline-none" />
                </div>
                <div>
                  <label className="block text-slate-400 text-sm font-medium mb-1">Catégorie</label>
                  <select value={category} onChange={e => setCategory(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-bar-accent outline-none">
                    {categories.map(c => <option key={c.id} value={c.name}>{c.name}</option>)}
                  </select>
                </div>
              </div>

              <div className="bg-slate-800/50 p-4 rounded-xl border border-slate-700/50 space-y-4">
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-slate-400 text-xs font-bold mb-1 uppercase">Coût Achat</label>
                        <input type="number" step="0.01" value={costPrice} onChange={e => setCostPrice(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-2 text-white text-sm focus:border-bar-accent outline-none" />
                    </div>
                    <div>
                        <label className="block text-slate-400 text-xs font-bold mb-1 uppercase">Prix Vente</label>
                        <input type="number" step="0.1" required value={price} onChange={e => setPrice(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-2 text-white font-bold text-sm focus:border-bar-accent outline-none" />
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-slate-400 text-xs font-bold mb-1 uppercase">Stock Initial</label>
                        <input type="number" value={stock} onChange={e => setStock(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-2 text-white text-sm focus:border-bar-accent outline-none" />
                    </div>
                    <div>
                        <label className="block text-red-400 text-xs font-bold mb-1 uppercase">Seuil d'alerte</label>
                        <input type="number" value={alertThreshold} onChange={e => setAlertThreshold(e.target.value)} className="w-full bg-slate-950 border border-red-900/50 rounded-lg p-2 text-white text-sm focus:border-red-500 outline-none" placeholder="5" />
                    </div>
                  </div>

                  {price && (
                      <div className="flex justify-between items-center text-xs bg-slate-900 p-2 rounded-lg border border-slate-800">
                          <span className="text-slate-400">Projection Marge:</span>
                          <span className={`font-bold ${marginStats.value > 0 ? 'text-green-400' : 'text-slate-500'}`}>
                              {marginStats.value.toFixed(2)}{currency} ({isFinite(marginStats.percent) ? marginStats.percent.toFixed(0) : 0}%)
                          </span>
                      </div>
                  )}
              </div>

              <div>
                <label className="block text-slate-400 text-sm font-medium mb-1">Description</label>
                <textarea value={description} onChange={e => setDescription(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-bar-accent outline-none h-20" />
              </div>

              <div className="pt-4 flex gap-3">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-3 rounded-xl border border-slate-700 text-slate-300 font-medium hover:bg-slate-800">Annuler</button>
                <button type="submit" className="flex-1 py-3 rounded-xl bg-bar-accent text-white font-bold hover:bg-pink-600 shadow-lg shadow-bar-accent/20">
                  {editingProduct ? 'Enregistrer' : 'Ajouter au stock'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import { GoogleGenAI, Type } from "@google/genai";
import { GeneratedRecipe } from '../types';

// Fix: Directly initialize GoogleGenAI with process.env.API_KEY as per coding guidelines
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateCocktailRecipe = async (ingredients: string): Promise<GeneratedRecipe> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Crée une recette de cocktail unique et délicieuse (et si possible avec un nom amusant) en utilisant principalement ces ingrédients : ${ingredients}. Si les ingrédients sont incohérents, propose quelque chose de créatif quand même.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            ingredients: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            instructions: { type: Type.STRING },
            history: { type: Type.STRING, description: "Une courte histoire fictive ou réelle amusante sur ce cocktail" }
          },
          required: ["name", "ingredients", "instructions", "history"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as GeneratedRecipe;
  } catch (error) {
    console.error("Error generating recipe:", error);
    throw error;
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { Product, CategoryDef, StockEntry } from '../types';
import { addProduct, deleteProduct, updateProduct, replenishStock, getStockHistory } from '../services/db';
import { Plus, Trash2, Search, Package, X, Edit2, LayoutGrid, List, CheckCircle, XCircle, AlertTriangle, ArrowUp, History, ClipboardList } from 'lucide-react';
import { getIconComponent } from '../components/IconRegistry';

interface ProductsPageProps {
  products: Product[];
  categories: CategoryDef[];
  refreshData: () => void;
  currency: string;
}

export const Products: React.FC<ProductsPageProps> = ({ products, categories, refreshData, currency }) => {
  // View State
  const [viewMode, setViewMode] = useState<'grid' | 'list'>('grid');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedCategoryFilter, setSelectedCategoryFilter] = useState('All');

  // Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Product | null>(null);
  const [isRestockOpen, setIsRestockOpen] = useState(false);
  const [restockProduct, setRestockProduct] = useState<Product | null>(null);
  const [stockHistory, setStockHistory] = useState<StockEntry[]>([]);
  const [isHistoryViewOpen, setIsHistoryViewOpen] = useState(false);

  // Form State
  const [name, setName] = useState('');
  const [price, setPrice] = useState('');
  const [costPrice, setCostPrice] = useState('');
  const [stock, setStock] = useState('');
  const [alertThreshold, setAlertThreshold] = useState('');
  const [category, setCategory] = useState('');
  const [description, setDescription] = useState('');
  const [imageUrl, setImageUrl] = useState('');
  const [isAvailable, setIsAvailable] = useState(true);

  // Restock Form
  const [restockQty, setRestockQty] = useState('');
  const [restockNote, setRestockNote] = useState('');

  // --- ACTIONS ---

  const handleOpenModal = (product?: Product) => {
    if (product) {
        setEditingProduct(product);
        setName(product.name);
        setPrice(product.price.toString());
        setCostPrice(product.costPrice?.toString() || '0');
        setStock(product.stock?.toString() || '0');
        setAlertThreshold(product.alertThreshold?.toString() || '5');
        setCategory(product.category);
        setDescription(product.description || '');
        setImageUrl(product.image || '');
        setIsAvailable(product.isAvailable !== undefined ? product.isAvailable : true);
        setStockHistory(getStockHistory(product.id));
    } else {
        setEditingProduct(null);
        setName('');
        setPrice('');
        setCostPrice('');
        setStock('');
        setAlertThreshold('5');
        setCategory(categories.length > 0 ? categories[0].name : '');
        setDescription('');
        setImageUrl('');
        setIsAvailable(true);
        setStockHistory([]);
    }
    setIsModalOpen(true);
  };

  const handleOpenRestock = (product: Product) => {
      setRestockProduct(product);
      setRestockQty('');
      setRestockNote('');
      setStockHistory(getStockHistory(product.id));
      setIsRestockOpen(true);
  };

  const handleViewHistory = (product: Product) => {
      setRestockProduct(product);
      setStockHistory(getStockHistory(product.id));
      setIsHistoryViewOpen(true);
  };

  const handleSave = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !price) return;

    const catToUse = category || (categories.length > 0 ? categories[0].name : 'Divers');
    const imageToUse = imageUrl || `https://picsum.photos/200/200?random=${Date.now()}`;
    const stockVal = parseInt(stock) || 0;
    const thresholdVal = parseInt(alertThreshold) || 5;
    const costVal = parseFloat(costPrice) || 0;
    const priceVal = parseFloat(price);

    if (editingProduct) {
        const updated: Product = {
            ...editingProduct,
            name,
            price: priceVal,
            costPrice: costVal,
            stock: stockVal,
            alertThreshold: thresholdVal,
            category: catToUse,
            description,
            image: imageToUse,
            isAvailable
        };
        updateProduct(updated);
    } else {
        const newProduct: Product = {
            id: Math.random().toString(36).substr(2, 9),
            name,
            price: priceVal,
            costPrice: costVal,
            stock: stockVal,
            alertThreshold: thresholdVal,
            category: catToUse,
            description,
            image: imageToUse,
            isAvailable
        };
        addProduct(newProduct);
    }

    refreshData();
    setIsModalOpen(false);
  };

  const handleRestockSave = (e: React.FormEvent) => {
      e.preventDefault();
      if (!restockProduct || !restockQty) return;
      const qty = parseInt(restockQty);
      if (isNaN(qty) || qty === 0) return;

      replenishStock(restockProduct.id, qty, restockNote || 'Réapprovisionnement manuel');
      refreshData();
      setIsRestockOpen(false);
  };

  const handleDelete = (id: string) => {
    if (confirm('Êtes-vous sûr de vouloir supprimer ce produit ?')) {
      deleteProduct(id);
      refreshData();
    }
  };

  const handleToggleAvailability = (product: Product, e: React.MouseEvent) => {
      e.stopPropagation();
      const updated = { ...product, isAvailable: !product.isAvailable };
      updateProduct(updated);
      refreshData();
  };

  // --- CALCULATIONS ---
  const calculateMargin = () => {
      const p = parseFloat(price) || 0;
      const c = parseFloat(costPrice) || 0;
      if (p === 0) return { value: 0, percent: 0 };
      const margin = p - c;
      const percent = (margin / p) * 100;
      return { value: margin, percent };
  };
  const marginStats = calculateMargin();

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
        const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                              p.category.toLowerCase().includes(searchQuery.toLowerCase());
        const matchesCategory = selectedCategoryFilter === 'All' || p.category === selectedCategoryFilter;
        return matchesSearch && matchesCategory;
    });
  }, [products, searchQuery, selectedCategoryFilter]);

  const getCategoryIcon = (catName: string) => {
    const cat = categories.find(c => c.name === catName);
    return cat ? cat.icon : 'Shapes';
  };

  const getStockStatus = (product: Product) => {
      if (product.stock <= 0) return { label: 'RUPTURE', color: 'text-red-500 bg-red-500/10 border-red-500/30', alert: true, critical: true };
      if (product.stock <= product.alertThreshold) return { label: 'STOCK FAIBLE', color: 'text-orange-500 bg-orange-500/10 border-orange-500/30', alert: true, critical: false };
      return { label: 'EN STOCK', color: 'text-green-500 bg-green-500/10 border-green-500/20', alert: false, critical: false };
  };

  return (
    <div className="p-4 md:p-8 h-full overflow-y-auto bg-slate-950 flex flex-col no-scrollbar">
      {/* HEADER */}
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4 shrink-0">
        <div>
          <h1 className="text-3xl font-bold text-white flex items-center gap-3">
            <Package className="text-bar-accent" />
            Stock & Inventaire
          </h1>
          <p className="text-slate-400 mt-1">Alertes de rupture et traçabilité des entrées</p>
        </div>

        <button 
          onClick={() => handleOpenModal()}
          className="bg-bar-accent hover:bg-pink-600 text-white font-bold py-3 px-6 rounded-xl flex items-center gap-2 transition-colors shadow-lg shadow-bar-accent/25"
        >
          <Plus size={20} />
          Nouveau Produit
        </button>
      </div>

      {/* CONTROLS BAR */}
      <div className="bg-slate-900 border border-slate-800 rounded-xl p-3 mb-6 flex flex-col md:flex-row gap-3 items-center sticky top-0 z-10 shadow-md">
          <div className="relative flex-1 w-full">
             <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
             <input 
               type="text" 
               placeholder="Rechercher par nom..." 
               className="w-full bg-slate-950 border border-slate-800 rounded-lg py-2 pl-10 pr-4 text-white focus:ring-2 focus:ring-bar-accent outline-none"
               value={searchQuery}
               onChange={(e) => setSearchQuery(e.target.value)}
             />
          </div>

          <div className="w-full md:w-auto">
             <select 
               value={selectedCategoryFilter}
               onChange={(e) => setSelectedCategoryFilter(e.target.value)}
               className="w-full bg-slate-950 border border-slate-800 rounded-lg py-2 px-4 text-white outline-none focus:border-bar-accent cursor-pointer"
             >
                <option value="All">Toutes catégories</option>
                {categories.map(cat => (
                    <option key={cat.id} value={cat.name}>{cat.name}</option>
                ))}
             </select>
          </div>

          <div className="flex bg-slate-950 rounded-lg p-1 border border-slate-800">
             <button onClick={() => setViewMode('grid')} className={`p-2 rounded-md transition-colors ${viewMode === 'grid' ? 'bg-slate-800 text-bar-accent' : 'text-slate-400 hover:text-white'}`}><LayoutGrid size={18} /></button>
             <button onClick={() => setViewMode('list')} className={`p-2 rounded-md transition-colors ${viewMode === 'list' ? 'bg-slate-800 text-bar-accent' : 'text-slate-400 hover:text-white'}`}><List size={18} /></button>
          </div>
      </div>

      {/* PRODUCTS DISPLAY */}
      <div className="flex-1 pb-24 md:pb-0">
        {viewMode === 'grid' ? (
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                {filteredProducts.map(product => {
                    const Icon = getIconComponent(getCategoryIcon(product.category));
                    const status = getStockStatus(product);
                    return (
                        <div key={product.id} className={`bg-slate-900 border rounded-xl overflow-hidden shadow-lg group flex flex-col h-full transition-all ${product.isAvailable === false ? 'opacity-70 grayscale-[0.3]' : ''} ${status.critical ? 'border-red-500/40 ring-1 ring-red-500/20' : 'border-slate-800 hover:border-slate-700'}`}>
                            <div className="relative h-40 w-full overflow-hidden bg-slate-800 flex items-center justify-center">
                                <Icon className="text-bar-accent w-14 h-14 drop-shadow-lg transform group-hover:scale-110 transition-transform duration-300" />
                                <div className="absolute top-2 right-2 flex flex-col gap-2 items-end">
                                     <span className={`text-[10px] font-bold px-2 py-1 rounded shadow-sm border flex items-center gap-1 backdrop-blur-md ${status.color} ${status.alert ? 'animate-pulse' : ''}`}>
                                         {status.alert && <AlertTriangle size={10} />}
                                         {status.label}: {product.stock}
                                     </span>
                                </div>
                            </div>
                            <div className="p-4 flex-1 flex flex-col">
                                <div className="flex justify-between items-start mb-4">
                                    <div className="min-w-0">
                                        <h3 className="font-bold text-white text-base leading-tight truncate">{product.name}</h3>
                                        <p className="text-xs text-slate-500 uppercase mt-0.5">{product.category}</p>
                                    </div>
                                    <span className="font-bold text-bar-accent bg-slate-950 px-2 py-1 rounded border border-slate-800 text-sm">{product.price.toFixed(2)}{currency}</span>
                                </div>

                                <div className="grid grid-cols-4 gap-2 mt-auto">
                                    <button 
                                      onClick={() => handleOpenRestock(product)}
                                      className="py-2 bg-green-500/10 hover:bg-green-500 text-green-500 hover:text-white rounded-lg transition-colors flex items-center justify-center border border-green-500/30"
                                      title="Réapprovisionner"
                                    >
                                        <ArrowUp size={16} />
                                    </button>
                                    <button 
                                      onClick={() => handleViewHistory(product)}
                                      className="py-2 bg-blue-500/10 hover:bg-blue-500 text-blue-500 hover:text-white rounded-lg transition-colors flex items-center justify-center border border-blue-500/30"
                                      title="Historique de stock"
                                    >
                                        <History size={16} />
                                    </button>
                                    <button 
                                      onClick={() => handleOpenModal(product)}
                                      className="py-2 bg-slate-800 hover:bg-slate-700 text-slate-300 rounded-lg transition-colors flex items-center justify-center border border-slate-700"
                                      title="Modifier"
                                    >
                                      <Edit2 size={16} />
                                    </button>
                                    <button 
                                      onClick={() => handleDelete(product.id)}
                                      className="py-2 bg-slate-800 hover:bg-red-600 text-slate-400 hover:text-white rounded-lg transition-colors flex items-center justify-center border border-slate-700"
                                      title="Supprimer"
                                    >
                                      <Trash2 size={16} />
                                    </button>
                                </div>
                            </div>
                        </div>
                    );
                })}
             </div>
        ) : (
             <div className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden shadow-lg overflow-x-auto">
                <table className="w-full text-left border-collapse">
                    <thead className="bg-slate-800/50 text-slate-400 text-xs uppercase font-medium">
                        <tr>
                            <th className="p-4">Produit</th>
                            <th className="p-4">Catégorie</th>
                            <th className="p-4 text-center">Stock Actuel</th>
                            <th className="p-4 text-center">Alerte</th>
                            <th className="p-4 text-right">Prix</th>
                            <th className="p-4 text-center">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-800">
                        {filteredProducts.map(product => {
                            const status = getStockStatus(product);
                            return (
