          <Plus size={20} />Nouvelle Table
        </button>
      </div>

      <div className="flex overflow-x-auto no-scrollbar border-b border-slate-800 mb-0 shrink-0">
         {allZones.map(zone => (
            <button key={zone} onClick={() => setActiveZone(zone)} className={`px-6 py-4 font-bold text-sm whitespace-nowrap transition-all relative ${activeZone === zone ? 'text-bar-accent bg-slate-900 rounded-t-xl border-t border-x border-slate-800 bottom-[-1px] z-10' : 'text-slate-400 hover:text-white hover:bg-slate-800/50 rounded-t-xl border border-transparent'}`}>
              {zone}
            </button>
         ))}
      </div>

      <div className="bg-slate-900 border border-slate-800 rounded-b-xl rounded-tr-xl p-6 shadow-lg flex-1 min-h-[300px]">
         <div className="flex items-center gap-3 mb-6 pb-4 border-b border-slate-800/50">
            <div className="bg-slate-800 p-2 rounded-lg"><MapPin size={20} className="text-bar-accent" /></div>
            <h2 className="text-xl font-bold text-white flex-1">{activeZone}</h2>
            <span className="text-slate-400 text-sm bg-slate-950 px-3 py-1 rounded-full border border-slate-800">{currentZoneTables.length} table{currentZoneTables.length > 1 ? 's' : ''}</span>
         </div>

         {currentZoneTables.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-20 text-slate-500 border-2 border-dashed border-slate-800 rounded-xl bg-slate-950/30">
                <Layout size={48} className="mb-4 opacity-50" /><p className="text-lg font-medium mb-2">Zone vide</p>
                <button onClick={openModal} className="mt-4 text-bar-accent hover:underline font-bold">Ajouter une table ici</button>
            </div>
         ) : (
            <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-4">
              {currentZoneTables.map(table => (
                <div key={table.id} className="bg-slate-800 p-4 rounded-xl flex flex-col items-center justify-between group relative hover:ring-2 hover:ring-bar-accent transition-all h-32 shadow-md">
                  <div className="text-slate-500 mb-2 mt-2"><Armchair size={32} /></div>
                  <span className="font-bold text-white text-lg">{table.name}</span>
                  <button onClick={() => setDeleteConfirmId(table.id)} className="absolute top-2 right-2 text-slate-600 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity bg-slate-900/50 p-1.5 rounded-full backdrop-blur-sm"><Trash2 size={14} /></button>
                </div>
              ))}
              <button onClick={openModal} className="border-2 border-dashed border-slate-700 hover:border-bar-accent hover:bg-slate-800/50 rounded-xl flex flex-col items-center justify-center h-32 transition-all group">
                  <div className="w-10 h-10 rounded-full bg-slate-800 group-hover:bg-bar-accent flex items-center justify-center mb-2"><Plus size={20} className="text-slate-400 group-hover:text-white" /></div>
                  <span className="text-slate-500 group-hover:text-white font-medium text-sm">Ajouter</span>
              </button>
            </div>
         )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-2xl shadow-2xl p-6 relative">
            <button onClick={() => setIsModalOpen(false)} className="absolute top-4 right-4 text-slate-400 hover:text-white"><X size={24} /></button>
            <h2 className="text-2xl font-bold text-white mb-6">Ajouter une Table</h2>
            <form onSubmit={handleAddTable} className="space-y-4">
