              </div>
              <div>
                <label className="block text-slate-400 text-sm font-medium mb-1">Zone</label>
                <div className="grid grid-cols-3 gap-2 mb-2">
                  {defaultZones.map(z => <button key={z} type="button" onClick={() => setNewZone(z)} className={`py-2 px-1 rounded-lg text-sm font-medium transition-colors ${newZone === z ? 'bg-bar-accent text-white' : 'bg-slate-950 border border-slate-800 text-slate-400 hover:text-white'}`}>{z}</button>)}
                </div>
                <input type="text" value={newZone} onChange={e => setNewZone(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-white focus:border-bar-accent outline-none text-sm" placeholder="Ou nouvelle zone..." />
              </div>
              <div className="flex gap-3 pt-4">
                <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-3 rounded-xl border border-slate-700 text-slate-300 font-medium hover:bg-slate-800">Annuler</button>
                <button type="submit" className="flex-1 py-3 rounded-xl bg-bar-accent text-white font-bold hover:bg-pink-600 shadow-lg shadow-bar-accent/20">Créer</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {deleteConfirmId && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-in fade-in duration-200">
           <div className="bg-slate-900 border border-red-500/30 w-full max-w-sm rounded-2xl shadow-2xl p-6 text-center animate-in zoom-in duration-300">
              <div className="bg-red-500/10 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 border border-red-500/20"><AlertTriangle size={32} className="text-red-500" /></div>
              <h2 className="text-xl font-bold text-white mb-2">Supprimer la table ?</h2>
