                        <h4 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-6">Tableau de Bord</h4>

                        <div className="space-y-6">
                            <div className="p-4 bg-slate-950 border border-slate-800 rounded-2xl">
