import React, { useState, useMemo } from 'react';
import { Order, Product, PaymentMethod } from '../types';
import { FileBarChart, CalendarRange, Download, ChevronDown, PieChart, TrendingUp, Package, Wallet } from 'lucide-react';

interface ReportsPageProps {
  orders: Order[];
  products: Product[];
  currency: string;
}

type Period = 'TODAY' | 'WEEK' | 'MONTH' | 'ALL';

export const ReportsPage: React.FC<ReportsPageProps> = ({ orders, products, currency }) => {
  const [period, setPeriod] = useState<Period>('TODAY');

  const filteredOrders = useMemo(() => {
    const now = new Date();
    return orders.filter(order => {
      const d = new Date(order.timestamp);
      if (period === 'TODAY') return d.toDateString() === now.toDateString();
      if (period === 'WEEK') {
        const weekAgo = new Date();
        weekAgo.setDate(now.getDate() - 7);
        return d >= weekAgo;
      }
      if (period === 'MONTH') {
        return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
      }
      return true;
    });
  }, [orders, period]);

  // Calculations for tables
  const reportData = useMemo(() => {
    const categories: Record<string, { total: number; qty: number }> = {};
    const items: Record<string, { total: number; qty: number; category: string }> = {};
    const payments: Record<string, number> = {
      [PaymentMethod.CASH]: 0,
      [PaymentMethod.CARD]: 0,
      [PaymentMethod.MOBILE_MONEY]: 0,
      [PaymentMethod.TAB]: 0,
    };

    filteredOrders.forEach(order => {
      if (order.paymentMethod) {
        payments[order.paymentMethod] = (payments[order.paymentMethod] || 0) + order.total;
      }

      order.items.forEach(item => {
        const product = products.find(p => p.name === item.name);
        const catName = product ? product.category : 'Divers';

        // Categories
        if (!categories[catName]) categories[catName] = { total: 0, qty: 0 };
        categories[catName].total += (item.price * item.quantity);
        categories[catName].qty += item.quantity;

        // Items
        if (!items[item.name]) items[item.name] = { total: 0, qty: 0, category: catName };
        items[item.name].total += (item.price * item.quantity);
        items[item.name].qty += item.quantity;
      });
    });

    return { 
      categories: Object.entries(categories).sort((a,b) => b[1].total - a[1].total),
      items: Object.entries(items).sort((a,b) => b[1].total - a[1].total),
      payments: Object.entries(payments).filter(([_, val]) => val > 0)
    };
  }, [filteredOrders, products]);

  const totalRevenue = filteredOrders.reduce((sum, o) => sum + o.total, 0);

  return (
    <div className="p-4 md:p-8 h-full overflow-y-auto bg-slate-950 no-scrollbar">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h1 className="text-3xl font-bold text-white flex items-center gap-3">
            <FileBarChart className="text-bar-accent" />
            Rapports de Vente
          </h1>
          <p className="text-slate-400 mt-1">Analyse détaillée des revenus et volumes</p>
        </div>

        <div className="flex items-center gap-3 bg-slate-900 p-1.5 rounded-xl border border-slate-800">
          {(['TODAY', 'WEEK', 'MONTH', 'ALL'] as Period[]).map((p) => (
            <button
              key={p}
              onClick={() => setPeriod(p)}
              className={`px-4 py-2 rounded-lg text-sm font-bold transition-all ${
                period === p ? 'bg-bar-accent text-white shadow-lg shadow-bar-accent/20' : 'text-slate-400 hover:text-white'
              }`}
            >
              {p === 'TODAY' ? "Aujourd'hui" : p === 'WEEK' ? '7 Jours' : p === 'MONTH' ? 'Mois' : 'Global'}
            </button>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 mb-8">
        {/* Sales by Category Table */}
        <div className="lg:col-span-2 bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden shadow-lg">
          <div className="p-5 border-b border-slate-800 bg-slate-800/50 flex justify-between items-center">
            <h3 className="font-bold text-white flex items-center gap-2">
              <PieChart size={18} className="text-blue-400" />
              Répartition par Catégorie
            </h3>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm text-slate-400">
              <thead className="bg-slate-950 text-slate-500 uppercase text-[10px] font-bold tracking-wider">
                <tr>
                  <th className="p-4">Catégorie</th>
                  <th className="p-4 text-center">Volume</th>
                  <th className="p-4 text-right">Chiffre d'Affaires</th>
                  <th className="p-4 text-right">% Part</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-800">
                {reportData.categories.map(([name, data]) => (
                  <tr key={name} className="hover:bg-slate-800/30 transition-colors">
                    <td className="p-4 font-bold text-white">{name}</td>
                    <td className="p-4 text-center">{data.qty}</td>
                    <td className="p-4 text-right text-white font-mono">{data.total.toFixed(2)}{currency}</td>
                    <td className="p-4 text-right">
                       <span className="bg-blue-500/10 text-blue-400 px-2 py-0.5 rounded text-[10px] font-bold">
                         {((data.total / totalRevenue) * 100).toFixed(1)}%
                       </span>
                    </td>
                  </tr>
                ))}
                {reportData.categories.length === 0 && (
                  <tr><td colSpan={4} className="p-10 text-center italic text-slate-600">Aucune vente enregistrée sur cette période.</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>

        {/* Payment Methods Breakdown */}
        <div className="bg-slate-900 border border-slate-800 rounded-2xl overflow-hidden shadow-lg h-fit">
          <div className="p-5 border-b border-slate-800 bg-slate-800/50 flex justify-between items-center">
            <h3 className="font-bold text-white flex items-center gap-2">
              <Wallet size={18} className="text-green-400" />
              Modes de Paiement
            </h3>
          </div>
          <div className="p-5 space-y-4">
            {reportData.payments.map(([method, val]) => (
              <div key={method} className="bg-slate-950 p-4 rounded-xl border border-slate-800">
                <div className="flex justify-between items-center mb-2">
