export const getOrders = (): Order[] => {
  if (!db) return [];
  try {
      const stmt = db.prepare("SELECT * FROM orders ORDER BY timestamp DESC");
      const orders: Order[] = [];
      while (stmt.step()) {
        const row = stmt.getAsObject();
        const itemsStmt = db.prepare("SELECT * FROM order_items WHERE order_id = ?");
        itemsStmt.bind([row.id]);
        const items: CartItem[] = [];
        while (itemsStmt.step()) {
          const itemRow = itemsStmt.getAsObject();
          items.push({ 
            id: itemRow.id.toString(), 
            name: itemRow.name, 
            price: itemRow.price, 
            costPrice: itemRow.cost_price || 0, 
            stock: 0, 
            alertThreshold: 0, 
            quantity: itemRow.quantity, 
            category: 'Divers' as any 
          });
        }
        itemsStmt.free();
        orders.push({
          id: row.id, total: row.total, status: row.status as OrderStatus, timestamp: row.timestamp,
          tableNumber: row.table_number, tableName: row.table_name || '?', clientId: row.client_id,
          clientName: row.client_name, paymentMethod: row.payment_method as PaymentMethod, items: items
        });
      }
      stmt.free();
      return orders;
  } catch (e) { return []; }
};

export const insertOrder = (order: Order) => {
  if (!db) return;
  db.run("INSERT INTO orders (id, total, status, timestamp, table_number, table_name, client_id, client_name, payment_method) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)", [
    order.id, order.total, order.status, order.timestamp, order.tableNumber || 0, order.tableName || 'Unknown', order.clientId || null, order.clientName || null, order.paymentMethod || null
  ]);
  const stmt = db.prepare("INSERT INTO order_items (order_id, name, price, cost_price, quantity) VALUES (?, ?, ?, ?, ?)");
  const stockStmt = db.prepare("UPDATE products SET stock = stock - ? WHERE name = ?");
  order.items.forEach(item => {
    stmt.run([order.id, item.name, item.price, item.costPrice || 0, item.quantity]);
    try { stockStmt.run([item.quantity, item.name]); } catch(e) {}
  });
  stmt.free();
  stockStmt.free();
  saveDB();
};

export const updateOrderStatusInDB = (orderId: string, status: OrderStatus) => {
  if (!db) return;
  db.run("UPDATE orders SET status = ? WHERE id = ?", [status, orderId]);
  saveDB();
};

export const processOrderPayment = (orderId: string, method: PaymentMethod, total: number, clientId?: string) => {
    if (!db) return;
    const numericTotal = Number(total);
    db.run("UPDATE orders SET status = ?, payment_method = ? WHERE id = ?", [OrderStatus.PAID, method, orderId]);
    if (clientId) {
        let sql = `UPDATE clients SET total_spent = total_spent + ?, loyalty_points = loyalty_points + ?, last_visit = ?`;
        const pointsEarned = Math.floor(numericTotal / 10);
        const params: any[] = [numericTotal, pointsEarned, Date.now()];
        if (method === PaymentMethod.TAB) {
            sql += `, balance = balance - ?`;
            params.push(numericTotal);
        }
        sql += ` WHERE id = ?`;
        params.push(clientId);
        db.run(sql, params);
    }
    saveDB();
};

import React, { useState, useMemo } from 'react';
import { Order, Product, PaymentMethod } from '../types';
import { 
  FileBarChart, CalendarRange, Download, PieChart, TrendingUp, 
  Package, Wallet, Target, Percent, CircleDollarSign, 
  History, Layers, Scale, Zap
} from 'lucide-react';

interface ReportsPageProps {
  orders: Order[];
  products: Product[];
  currency: string;
}

type Period = 'TODAY' | 'YESTERDAY' | 'WEEK' | 'MONTH' | 'LAST_MONTH' | 'ALL';

export const ReportsPage: React.FC<ReportsPageProps> = ({ orders, products, currency }) => {
  const [period, setPeriod] = useState<Period>('TODAY');

  const filteredOrders = useMemo(() => {
    const now = new Date();
    const today = new Date(now.getFullYear(), now.getMonth(), now.getDate());

    return orders.filter(order => {
      const d = new Date(order.timestamp);
      const orderDay = new Date(d.getFullYear(), d.getMonth(), d.getDate());

      if (period === 'TODAY') return orderDay.getTime() === today.getTime();

      if (period === 'YESTERDAY') {
        const yesterday = new Date(today);
        yesterday.setDate(today.getDate() - 1);
        return orderDay.getTime() === yesterday.getTime();
      }

      if (period === 'WEEK') {
        const weekAgo = new Date(today);
        weekAgo.setDate(today.getDate() - 7);
        return d >= weekAgo;
      }

      if (period === 'MONTH') {
        return d.getMonth() === now.getMonth() && d.getFullYear() === now.getFullYear();
      }

      if (period === 'LAST_MONTH') {
        const lastMonth = now.getMonth() === 0 ? 11 : now.getMonth() - 1;
        const lastMonthYear = now.getMonth() === 0 ? now.getFullYear() - 1 : now.getFullYear();
        return d.getMonth() === lastMonth && d.getFullYear() === lastMonthYear;
      }

      return true;
    });
  }, [orders, period]);

  const reportData = useMemo(() => {
    const categories: Record<string, { total: number; qty: number; cost: number }> = {};
    const items: Record<string, { total: number; qty: number; category: string; cost: number }> = {};
    const payments: Record<string, number> = {
      [PaymentMethod.CASH]: 0,
      [PaymentMethod.CARD]: 0,
      [PaymentMethod.MOBILE_MONEY]: 0,
      [PaymentMethod.TAB]: 0,
    };

    filteredOrders.forEach(order => {
      if (order.paymentMethod) {
        payments[order.paymentMethod] = (payments[order.paymentMethod] || 0) + order.total;
      }

      order.items.forEach(item => {
        // Utilisation du prix d'achat stocké dans la commande pour l'exactitude historique
        const historicalCost = item.costPrice || 0;
        const totalCost = historicalCost * item.quantity;
        const totalRev = item.price * item.quantity;

        // Trouver la catégorie actuelle pour le groupage
        const product = products.find(p => p.name === item.name);
        const catName = product ? product.category : 'Divers';

        // Categories stats
        if (!categories[catName]) categories[catName] = { total: 0, qty: 0, cost: 0 };
        categories[catName].total += totalRev;
        categories[catName].qty += item.quantity;
        categories[catName].cost += totalCost;

        // Items stats
        if (!items[item.name]) items[item.name] = { total: 0, qty: 0, category: catName, cost: 0 };
        items[item.name].total += totalRev;
        items[item.name].qty += item.quantity;
        items[item.name].cost += totalCost;
      });
    });

    return { 
      categories: Object.entries(categories).sort((a,b) => b[1].total - a[1].total),
      items: Object.entries(items).sort((a,b) => (b[1].total - b[1].cost) - (a[1].total - a[1].cost)), // Sort by Profit
      payments: Object.entries(payments).filter(([_, val]) => val > 0)
    };
  }, [filteredOrders, products]);

  const totalRevenue = filteredOrders.reduce((sum, o) => sum + o.total, 0);
  const totalCost = reportData.items.reduce((sum, [_, data]) => sum + data.cost, 0);
  const totalProfit = totalRevenue - totalCost;
  const marginRate = totalRevenue > 0 ? (totalProfit / totalRevenue) * 100 : 0;
  const avgBasket = filteredOrders.length > 0 ? totalRevenue / filteredOrders.length : 0;
  const avgMultiplier = totalCost > 0 ? totalRevenue / totalCost : 0;

  const exportToCSV = () => {
    const headers = ["Article", "Categorie", "Quantite", "CA", "Cout Achat", "Profit", "Marge %", "Multiplier"];
    const rows = reportData.items.map(([name, data]) => {
      const profit = data.total - data.cost;
      const margin = data.total > 0 ? (profit / data.total) * 100 : 0;
      const multiplier = data.cost > 0 ? data.total / data.cost : 0;
      return [
        name,
        data.category,
        data.qty,
        data.total.toFixed(2),
        data.cost.toFixed(2),
        profit.toFixed(2),
        margin.toFixed(1),
        multiplier.toFixed(2)
      ];
    });

    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n"
      + rows.map(e => e.join(",")).join("\n");

    const encodedUri = encodeURI(csvContent);
