                    <td colSpan={7} className="p-20 text-center italic text-slate-600 uppercase font-black tracking-widest opacity-20">
                        Aucune vente à analyser
                    </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

