            <button 
                onClick={() => setIsModalOpen(true)}
                className="flex-1 md:flex-none flex items-center justify-center gap-2 px-6 py-3 bg-slate-800 hover:bg-slate-700 text-white rounded-xl font-bold transition-all border border-slate-700"
            >
                <Plus size={20} /> Nouvelle Table
            </button>
        </div>
      </div>

      {/* Zone Tabs - Explicit and clear */}
      <div className="flex gap-2 mb-8 overflow-x-auto no-scrollbar pb-2">
         {zones.map(zone => (
           <button
             key={zone}
             onClick={() => setActiveZone(zone)}
             className={`px-5 py-3 rounded-xl font-black uppercase tracking-widest text-[10px] transition-all border flex items-center gap-2 ${
               activeZone === zone 
                ? 'bg-bar-accent border-bar-accent text-white shadow-lg shadow-bar-accent/20' 
                : 'bg-slate-900 border-slate-800 text-slate-500 hover:text-white'
             }`}
           >
             {ZONE_ICONS[zone] || <MapPin size={18} />}
             {zone}
             <span className="bg-slate-950/50 px-2 py-0.5 rounded-full text-[8px] opacity-70">
                {tables.filter(t => t.zone === zone).length}
             </span>
           </button>
         ))}
      </div>

      {/* Tables Grid */}
      <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6 gap-6">
        {currentTables.length > 0 ? currentTables.map(table => {
          const activeOrder = getTableCurrentOrder(table.name);
          const isOccupied = table.status === TableStatus.OCCUPIED;
          const isReserved = table.status === TableStatus.RESERVED;

          return (
            <div 
              key={table.id} 
              className={`relative rounded-3xl p-5 border-2 transition-all group flex flex-col h-48 shadow-2xl ${
                isOccupied 
                  ? 'bg-red-500/10 border-red-500/50 shadow-red-500/10' 
                  : isReserved
                    ? 'bg-amber-500/10 border-amber-500/50 shadow-amber-500/10'
                    : 'bg-slate-900 border-slate-800 hover:border-slate-700'
              } ${table.zone === 'VIP' && !isOccupied && !isReserved ? 'border-purple-500/20' : ''}`}
            >
              <div className="flex justify-between items-start mb-4">
                 <div className="flex flex-col">
                    <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">
                        {table.zone === 'VIP' ? 'Zone Prestige' : 'Table'}
                    </span>
                    <h3 className="text-2xl font-black text-white">{table.name}</h3>
                 </div>
                 <div className={`p-2.5 rounded-2xl ${
                    isOccupied ? 'bg-red-500 text-white shadow-lg shadow-red-500/30' : 
                    isReserved ? 'bg-amber-500 text-white shadow-lg shadow-amber-500/30' : 
                    table.zone === 'VIP' ? 'bg-purple-900/50 text-purple-400' : 'bg-slate-800 text-slate-500'
                 }`}>
                    {table.zone === 'VIP' ? <Crown size={20} /> : <Armchair size={20} />}
                 </div>
              </div>

              <div className="flex-1 flex flex-col justify-center">
                 {isOccupied && activeOrder ? (
                    <div className="animate-in fade-in duration-500">
                       <p className="text-2xl font-black text-red-500">{activeOrder.total.toFixed(2)}{currency}</p>
                       <p className="text-[10px] text-slate-500 font-bold flex items-center gap-1 mt-1 uppercase">
                          <Clock size={10} /> 
                          Occupée {Math.floor((Date.now() - activeOrder.timestamp) / 60000)}m
                       </p>
                    </div>
                 ) : isReserved ? (
                    <div className="text-amber-500 text-xs font-bold flex flex-col gap-1">
                       <div className="flex items-center gap-1">
                            <CalendarCheck size={14} /> 
                            <span>Réservée</span>
                       </div>
                       <span className="truncate text-[10px] text-slate-400 font-medium">
                          {table.reservationNote || 'Client attendu'}
                       </span>
                    </div>
                 ) : (
                    <span className="text-[10px] text-slate-600 font-black uppercase tracking-widest flex items-center gap-2">
                        <div className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></div>
                        Disponible
                    </span>
                 )}
              </div>

              <div className="flex gap-2 mt-4">
                 {isOccupied ? (
                    <button 
                       onClick={() => navigate('/kitchen')}
                       className="flex-1 bg-red-500 hover:bg-red-600 text-white py-2.5 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-1 shadow-lg shadow-red-500/20"
                    >
                       <Calculator size={12} /> Addition
                    </button>
                 ) : (
                    <button 
                       onClick={() => handleToggleReservation(table)}
                       className={`flex-1 py-2.5 rounded-xl text-[10px] font-black uppercase transition-all flex items-center justify-center gap-1 ${
                         isReserved 
                          ? 'bg-amber-500 text-white shadow-lg shadow-amber-500/20' 
                          : 'bg-slate-800 text-slate-400 hover:bg-amber-500/20 hover:text-amber-500'
                       }`}
                    >
                       <CalendarCheck size={12} /> {isReserved ? 'Libérer' : 'Réserver'}
                    </button>
                 )}
                 <button 
                    onClick={() => navigate('/pos', { state: { tableName: table.name } })}
                    className={`w-10 h-10 rounded-xl transition-all flex items-center justify-center border ${
                        isOccupied ? 'bg-slate-800 border-slate-700 text-white' : 'bg-slate-800 hover:bg-bar-accent border-slate-700 text-slate-400 hover:text-white'
                    }`}
                    title="Ouvrir la caisse"
                 >
                    <LogIn size={18} />
                 </button>
              </div>

              <button 
                 onClick={() => { if(confirm('Supprimer cette table ?')) { deleteTable(table.id); refreshData(); }}}
                 className="absolute -top-2 -right-2 w-8 h-8 bg-slate-900 border border-slate-800 rounded-full flex items-center justify-center text-slate-600 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity shadow-lg"
              >
                 <Trash2 size={14} />
              </button>
            </div>
          );
        }) : (
            <div className="col-span-full py-20 text-center flex flex-col items-center gap-4 text-slate-600">
                <Armchair size={48} className="opacity-20" />
                <p className="font-black text-xs uppercase tracking-widest">Aucune table dans cette zone</p>
                <button onClick={() => setIsModalOpen(true)} className="text-bar-accent text-[10px] font-black uppercase hover:underline">Ajouter la première table</button>
            </div>
        )}

        {/* Add Table Placeholder */}
        <button 
           onClick={() => setIsModalOpen(true)}
           className="h-48 rounded-3xl border-2 border-dashed border-slate-800 hover:border-bar-accent hover:bg-bar-accent/5 transition-all flex flex-col items-center justify-center gap-3 text-slate-600 hover:text-bar-accent"
        >
           <div className="w-12 h-12 bg-slate-900 rounded-2xl flex items-center justify-center border border-slate-800">
              <Plus size={24} />
           </div>
           <span className="font-black text-[10px] uppercase tracking-widest">Ajouter Table</span>
        </button>
      </div>

      {/* Reservation Modal */}
      {reservationModalTable && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/95 backdrop-blur-md p-4 animate-in fade-in duration-200">
           <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-3xl shadow-2xl p-8 animate-in zoom-in duration-300">
              <h2 className="text-2xl font-black text-white mb-6 flex items-center gap-3 italic">
                 <CalendarCheck className="text-amber-500" /> RÉSERVATION
              </h2>
              <div className="mb-6 p-4 bg-slate-950 rounded-2xl border border-slate-800">
                 <p className="text-[10px] font-black text-slate-600 uppercase mb-1">Table sélectionnée</p>
                 <p className="text-xl font-black text-white">{reservationModalTable.name} ({reservationModalTable.zone})</p>
              </div>
              <div className="space-y-4 mb-8">
                 <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest">Note (Nom, Heure, Couverts)</label>
                 <input 
                   type="text" 
                   value={resNote} 
                   onChange={(e) => setResNote(e.target.value)}
                   className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-white focus:ring-2 focus:ring-amber-500 outline-none font-medium"
                   placeholder="Ex: Dupont - 20h30 - 4 pers."
                   autoFocus
                 />
              </div>
              <div className="flex gap-4">
                 <button onClick={() => setReservationModalTable(null)} className="flex-1 py-4 text-slate-400 font-bold uppercase tracking-widest text-xs">Annuler</button>
                 <button onClick={submitReservation} className="flex-1 py-4 bg-amber-500 hover:bg-amber-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-lg shadow-amber-900/20 transition-all">Confirmer</button>
              </div>
           </div>
        </div>
      )}

      {/* New Table Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/95 backdrop-blur-md p-4 animate-in fade-in duration-200">
           <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-3xl shadow-2xl p-8 animate-in zoom-in duration-300">
              <h2 className="text-2xl font-black text-white mb-6 flex items-center gap-3 italic">
                 <Plus className="text-bar-accent" /> NOUVELLE TABLE
              </h2>
              <form onSubmit={handleAddTable} className="space-y-5">
                 <div>
                    <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Nom / Numéro</label>
                    <input type="text" value={newName} onChange={e => setNewName(e.target.value)} required className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-white focus:ring-2 focus:ring-bar-accent outline-none font-bold" autoFocus placeholder="Ex: T5, VIP-2..." />
                 </div>
                 <div>
                    <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-1">Zone de salle</label>
                    <select 
                        value={newZone} 
                        onChange={e => setNewZone(e.target.value)}
                        className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-white focus:ring-2 focus:ring-bar-accent outline-none font-bold appearance-none"
                    >
                        {zones.map(z => <option key={z} value={z}>{z}</option>)}
                    </select>
                 </div>
                 <div className="flex gap-4 pt-4">
                    <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-4 text-slate-400 font-bold uppercase tracking-widest text-xs">Annuler</button>
                    <button type="submit" className="flex-1 py-4 bg-bar-accent hover:bg-pink-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs transition-all shadow-lg shadow-bar-accent/20">Créer</button>
                 </div>
              </form>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect } from 'react';
import { Product, CartItem, CategoryDef, TableDef, Order, Client, TableStatus, OrderStatus } from '../types';
import { ProductCard } from '../components/ProductCard';
import { getIconComponent } from '../components/IconRegistry';
import { Search, ShoppingCart, Trash2, CreditCard, ChevronUp, Armchair, X, User, UserPlus, Plus, Minus, Info } from 'lucide-react';
import { useLocation } from 'react-router-dom';

interface POSProps {
  products: Product[];
  categories: CategoryDef[];
  tables: TableDef[];
  activeOrders: Order[];
  clients: Client[];
  cart: CartItem[];
  addToCart: (product: Product) => void;
  updateCartItemQuantity: (productId: string, quantity: number) => void;
  removeFromCart: (productId: string) => void;
  clearCart: () => void;
  placeOrder: (tableName: string, client?: Client | null) => void;
  currency: string;
}

export const POS: React.FC<POSProps> = ({ 
  products, 
  categories, 
  tables, 
  activeOrders,
  clients,
  cart, 
  addToCart, 
  updateCartItemQuantity,
  removeFromCart, 
  clearCart,
  placeOrder,
  currency
}) => {
  const location = useLocation();
  const [selectedCategory, setSelectedCategory] = useState<string>('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [selectedTable, setSelectedTable] = useState<string>('');
  const [selectedClient, setSelectedClient] = useState<Client | null>(null);
  const [showTableSelector, setShowTableSelector] = useState(false);
  const [showClientSelector, setShowClientSelector] = useState(false);
  const [clientSearch, setClientSearch] = useState('');

  // Gestion du chargement d'une table via navigation state
  useEffect(() => {
    if (location.state?.tableName) {
        setSelectedTable(location.state.tableName);
        // Si la table est occupée, on pourrait charger l'addition, 
        // mais ici on laisse l'utilisateur AJOUTER à la table.
    }
  }, [location.state]);

  const filteredProducts = useMemo(() => {
    return products.filter(product => {
      const matchesCategory = selectedCategory === 'All' || product.category === selectedCategory;
      const matchesSearch = product.name.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery, products]);

  // Fix: Explicitly type filteredClients to resolve line 300 'unknown' error and ensure map() is available
  const filteredClients: Client[] = useMemo(() => {
    return clients.filter(c => c.name.toLowerCase().includes(clientSearch.toLowerCase()));
  }, [clients, clientSearch]);

  const cartTotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
  const totalItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  const getTableOrder = (tableName: string) => {
    return activeOrders.find(o => o.tableName === tableName && o.status !== OrderStatus.PAID);
  };

  const handlePlaceOrder = () => {
    if (cart.length === 0) return;
    if (!selectedTable) {
        setShowTableSelector(true);
        return;
    }
    placeOrder(selectedTable, selectedClient);
    setIsCartOpen(false);
    setSelectedTable('');
    setSelectedClient(null);
  };

  // Fix: Explicitly type tablesByZone Record to avoid 'unknown' mapping errors during rendering
  const tablesByZone: Record<string, TableDef[]> = useMemo(() => {
    return tables.reduce((acc, table) => {
        if (!acc[table.zone]) acc[table.zone] = [];
        acc[table.zone].push(table);
        return acc;
    }, {} as Record<string, TableDef[]>);
  }, [tables]);

  const activeTableOrder = selectedTable ? getTableOrder(selectedTable) : null;

  return (
    <div className="h-full flex flex-col md:flex-row overflow-hidden bg-slate-950">

      {/* Main Content (Menu) */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative">
        {/* Header */}
        <div className="p-4 md:p-6 bg-slate-900 border-b border-slate-800 sticky top-0 z-20">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <h1 className="text-2xl font-black text-white italic tracking-tighter">CAISSE</h1>
            <div className="relative w-full md:w-64">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Rechercher..." 
                className="w-full bg-slate-950 border border-slate-800 rounded-full py-2.5 pl-10 pr-4 text-white focus:ring-2 focus:ring-bar-accent outline-none placeholder-slate-600"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
              />
            </div>
          </div>

          {/* Categories */}
          <div className="flex gap-2 overflow-x-auto mt-4 pb-2 no-scrollbar">
            <button
                onClick={() => setSelectedCategory('All')}
                className={`px-5 py-2.5 rounded-xl whitespace-nowrap text-xs font-black uppercase tracking-widest transition-all ${
                  selectedCategory === 'All' 
                    ? 'bg-bar-accent text-white shadow-lg' 
                    : 'bg-slate-950 text-slate-500 hover:text-white border border-slate-800'
                }`}
              >
                Tout
              </button>
            {categories.map((cat) => {
              const Icon = getIconComponent(cat.icon);
              return (
                <button
                  key={cat.id}
                  onClick={() => setSelectedCategory(cat.name)}
                  className={`px-5 py-2.5 rounded-xl whitespace-nowrap text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 border ${
                    selectedCategory === cat.name
                      ? 'bg-bar-accent border-bar-accent text-white shadow-lg' 
                      : 'bg-slate-950 border-slate-800 text-slate-500 hover:text-white'
                  }`}
                >
                  <Icon size={14} />
                  {cat.name}
                </button>
              );
            })}
          </div>
        </div>

        {/* Product Grid */}
        <div className="flex-1 overflow-y-auto p-4 md:p-6 pb-24 md:pb-6 no-scrollbar">
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 gap-4">
            {filteredProducts.map(product => (
              <ProductCard 
                key={product.id} 
                product={product} 
                iconName={categories.find(c => c.name === product.category)?.icon || 'Shapes'}
                onAdd={addToCart}
                currency={currency}
              />
            ))}
          </div>
        </div>
      </div>

      {/* Cart Sidebar */}
      <div className={`
        fixed inset-0 z-[60] md:static md:z-0 md:w-96 bg-slate-900 border-l border-slate-800 flex flex-col transition-transform duration-300 transform
        ${isCartOpen ? 'translate-y-0' : 'translate-y-[100%] md:translate-y-0'}
      `}>
         {/* Mobile Handle */}
         <div className="md:hidden flex justify-center pt-2 pb-1" onClick={() => setIsCartOpen(false)}>
            <div className="w-12 h-1.5 bg-slate-700 rounded-full"></div>
         </div>

         <div className="p-6 border-b border-slate-800 bg-slate-950/50">
           <div className="flex justify-between items-center mb-6">
             <div className="flex items-center gap-3">
               <h2 className="text-xl font-black text-white italic">TICKET</h2>
               <span className="bg-bar-accent text-white text-[10px] font-black px-2 py-0.5 rounded-full">{totalItems}</span>
             </div>

             <button 
              onClick={() => setShowTableSelector(true)}
              className={`flex items-center gap-2 px-4 py-2 rounded-xl text-xs font-black uppercase tracking-widest transition-all border ${
                selectedTable ? 'bg-bar-accent border-bar-accent text-white shadow-lg' : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-white'
              }`}
             >
               <Armchair size={16} />
               {selectedTable ? `TABLE ${selectedTable}` : 'CHOISIR TABLE'}
             </button>
           </div>

           {/* Table Status Alert */}
           {activeTableOrder && (
              <div className="mb-4 p-3 bg-red-500/10 border border-red-500/30 rounded-xl flex items-center gap-3 animate-in slide-in-from-top-2">
                 <div className="p-2 bg-red-500 rounded-lg text-white">
                    <Info size={16} />
                 </div>
                 <div className="flex-1">
                    <p className="text-[10px] font-black text-red-500 uppercase">Table Occupée</p>
                    <p className="text-xs text-slate-300">Articles ajoutés à l'addition ({activeTableOrder.total.toFixed(2)}{currency})</p>
                 </div>
              </div>
           )}

           <button 
             onClick={() => setShowClientSelector(true)}
             className={`w-full flex items-center justify-between px-4 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all border ${
               selectedClient ? 'bg-blue-500/10 border-blue-500/30 text-blue-400' : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-white'
             }`}
           >
             <div className="flex items-center gap-2">
                <User size={16} />
                {selectedClient ? selectedClient.name : 'Client invité'}
             </div>
             {selectedClient && <span className="text-[10px] bg-blue-500 text-white px-2 py-0.5 rounded-full">{selectedClient.loyaltyPoints} PTS</span>}
           </button>
         </div>

         <div className="flex-1 overflow-y-auto p-4 space-y-3 no-scrollbar">
           {cart.length === 0 ? (
             <div className="h-full flex flex-col items-center justify-center text-slate-700">
               <div className="p-6 bg-slate-950 rounded-full mb-4 border border-slate-800">
                  <ShoppingCart size={48} className="opacity-20" />
               </div>
               <p className="font-black text-[10px] uppercase tracking-widest">Le panier est vide</p>
             </div>
           ) : (
             cart.map(item => (
               <div key={item.id} className="flex justify-between items-center bg-slate-950/30 p-4 rounded-2xl border border-slate-800/50 group hover:border-bar-accent/50 transition-all">
                 <div className="flex items-center gap-4 flex-1">
                   <div className="flex items-center gap-2 bg-slate-900 rounded-xl p-1.5 border border-slate-800 shadow-inner">
                       <button 
                         onClick={() => updateCartItemQuantity(item.id, item.quantity - 1)}
                         className="w-8 h-8 flex items-center justify-center bg-slate-800 hover:bg-slate-700 text-slate-400 rounded-lg transition-colors"
                       >
                         <Minus size={14} />
                       </button>
                       <span className="w-8 text-center text-white text-sm font-black">{item.quantity}</span>
                        <button 
                         onClick={() => updateCartItemQuantity(item.id, item.quantity + 1)}
                         className="w-8 h-8 flex items-center justify-center bg-slate-800 hover:bg-slate-700 text-slate-400 rounded-lg transition-colors"
                       >
                         <Plus size={14} />
                       </button>
                   </div>
                   <div className="min-w-0">
                     <p className="text-white font-bold text-sm truncate">{item.name}</p>
                     <p className="text-bar-accent text-xs font-black">{item.price.toFixed(2)}{currency}</p>
                   </div>
                 </div>
                 <button 
                   onClick={() => removeFromCart(item.id)}
                   className="text-slate-700 hover:text-red-500 transition-colors p-2 ml-2"
                 >
                   <Trash2 size={18} />
                 </button>
               </div>
             ))
           )}
         </div>

         <div className="p-6 bg-slate-950 border-t border-slate-800">
           <div className="flex justify-between items-center mb-6">
             <span className="text-slate-500 font-black text-xs uppercase tracking-widest">Total Ticket</span>
             <span className="text-3xl font-black text-white">{cartTotal.toFixed(2)}{currency}</span>
           </div>
           <button 
             onClick={handlePlaceOrder}
             disabled={cart.length === 0}
             className="w-full bg-bar-accent hover:bg-pink-600 disabled:opacity-20 disabled:grayscale text-white font-black uppercase tracking-widest py-4 rounded-2xl shadow-xl shadow-bar-accent/25 transition-all flex items-center justify-center gap-3"
           >
             <CreditCard size={20} />
             {selectedTable ? (activeTableOrder ? 'Ajouter à la table' : 'Ouvrir Addition') : 'Choisir une Table'}
           </button>
         </div>
      </div>

      {/* Table Selector Modal - Enhanced */}
      {showTableSelector && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/95 backdrop-blur-sm p-4 animate-in fade-in duration-300">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-5xl max-h-[90vh] rounded-3xl shadow-2xl overflow-hidden flex flex-col animate-in zoom-in duration-300">
            <div className="p-8 border-b border-slate-800 flex justify-between items-center">
              <h2 className="text-2xl font-black text-white italic flex items-center gap-3">
                <Armchair className="text-bar-accent" /> SÉLECTION TABLE
              </h2>
              <button onClick={() => setShowTableSelector(false)} className="text-slate-400 hover:text-white bg-slate-800 p-2 rounded-full transition-colors"><X size={24} /></button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 no-scrollbar">
              <div className="space-y-10">
                {Object.entries(tablesByZone).map(([zone, zoneTables]) => (
                  <div key={zone}>
                    <h3 className="text-xs font-black text-slate-500 uppercase tracking-[0.3em] mb-4 ml-1">{zone}</h3>
                    <div className="grid grid-cols-2 sm:grid-cols-4 md:grid-cols-5 xl:grid-cols-6 gap-4">
                      {zoneTables.map(table => {
                        const order = getTableOrder(table.name);
                        const isOccupied = table.status === TableStatus.OCCUPIED;
                        const isReserved = table.status === TableStatus.RESERVED;
