export const getSetting = (key: string, defaultValue: string = ''): string => {
  if (!db) return defaultValue;
  try {
    const stmt = db.prepare("SELECT value FROM settings WHERE key = ?");
    stmt.bind([key]);
    if (stmt.step()) {
      const result = stmt.getAsObject();
      stmt.free();
      return result.value;
    }
    stmt.free();
    return defaultValue;
  } catch (e) {
    return defaultValue;
  }
};

