import React, { useState, useEffect } from 'react';
import { User, UserRole } from '../types';
import { Beer, ShieldCheck, User as UserIcon, LogIn, Lock, ArrowLeft, Delete, X, CheckCircle2 } from 'lucide-react';

interface LoginPageProps {
  onLogin: (user: User) => void;
  users: User[];
}

export const LoginPage: React.FC<LoginPageProps> = ({ onLogin, users }) => {
  const [step, setStep] = useState<'SELECT' | 'PIN'>('SELECT');
  const [selectedUser, setSelectedUser] = useState<User | null>(null);
  const [pin, setPin] = useState('');
  const [error, setError] = useState(false);
  const [isSuccess, setIsSuccess] = useState(false);

  const handleUserSelect = (user: User) => {
    setSelectedUser(user);
    setPin('');
    setError(false);
    setStep('PIN');
  };

  const handleBack = () => {
    setStep('SELECT');
    setSelectedUser(null);
    setPin('');
    setError(false);
  };

  const handleKeyPress = (num: string) => {
    if (pin.length < 4) {
      const newPin = pin + num;
      setPin(newPin);
      if (newPin.length === 4) {
        verifyPin(newPin);
      }
    }
  };

  const handleDelete = () => {
    setPin(prev => prev.slice(0, -1));
    setError(false);
  };

  const verifyPin = (inputPin: string) => {
    if (!selectedUser) return;

    // Si pas de PIN configuré, on laisse passer (ou on définit un PIN par défaut)
    const userPin = selectedUser.pin || '0000';

    if (inputPin === userPin) {
      setIsSuccess(true);
      setTimeout(() => {
        onLogin(selectedUser);
      }, 600);
    } else {
      setError(true);
      setTimeout(() => {
        setPin('');
        setError(false);
      }, 800);
    }
  };

  const getRoleBadge = (role: UserRole) => {
    switch (role) {
      case UserRole.ADMIN: return { label: 'Direction', color: 'text-purple-400 bg-purple-500/10 border-purple-500/20' };
      case UserRole.BARTENDER: return { label: 'Barman', color: 'text-blue-400 bg-blue-500/10 border-blue-500/20' };
      default: return { label: 'Service', color: 'text-emerald-400 bg-emerald-500/10 border-emerald-500/20' };
    }
  };

  return (
    <div className="h-screen w-screen bg-slate-950 flex flex-col items-center justify-center p-4 overflow-hidden relative">
      {/* Background Decor */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-bar-accent/10 blur-[120px] rounded-full pointer-events-none"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-purple-600/10 blur-[120px] rounded-full pointer-events-none"></div>

      <div className="max-w-4xl w-full z-10">
        {step === 'SELECT' ? (
          <div className="animate-in fade-in zoom-in-95 duration-500">
            <div className="text-center mb-12">
              <div className="w-20 h-20 bg-gradient-to-tr from-bar-accent to-purple-600 rounded-3xl flex items-center justify-center shadow-2xl shadow-bar-accent/20 mx-auto mb-6 transform hover:rotate-12 transition-transform cursor-pointer">
                <Beer className="text-white" size={40} />
              </div>
              <h1 className="text-4xl font-black text-white italic tracking-tighter mb-2 uppercase">BARFLOW AI</h1>
              <p className="text-slate-500 font-medium tracking-wide">AUTHENTIFICATION PERSONNELLE</p>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 max-h-[60vh] overflow-y-auto no-scrollbar p-2">
              {users.map((user) => {
                const badge = getRoleBadge(user.role);
                return (
                  <button
                    key={user.id}
                    onClick={() => handleUserSelect(user)}
                    className="group relative bg-slate-900/50 backdrop-blur-sm border border-slate-800 p-6 rounded-3xl flex flex-col items-center text-center hover:border-bar-accent/50 hover:bg-slate-900 transition-all hover:scale-[1.03] shadow-xl"
                  >
                    <div className="absolute top-4 right-4 opacity-0 group-hover:opacity-100 transition-opacity">
                        <LogIn size={18} className="text-bar-accent" />
                    </div>
                    <div className={`w-20 h-20 rounded-2xl flex items-center justify-center border-2 mb-4 transition-all group-hover:shadow-lg ${
                      user.role === UserRole.ADMIN ? 'bg-purple-500/10 border-purple-500/30 text-purple-400 group-hover:shadow-purple-500/20' :
                      user.role === UserRole.BARTENDER ? 'bg-blue-500/10 border-blue-500/30 text-blue-400 group-hover:shadow-blue-500/20' :
                      'bg-emerald-500/10 border-emerald-500/30 text-emerald-400 group-hover:shadow-emerald-500/20'
                    }`}>
                      <span className="text-2xl font-black">{user.name.charAt(0).toUpperCase()}</span>
                    </div>
                    <h3 className="text-white font-black text-xl mb-2 italic">{user.name}</h3>
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border ${badge.color}`}>
                      {badge.label}
                    </span>
                  </button>
                );
              })}
              {users.length === 0 && (
                <div className="col-span-full text-center p-12 bg-slate-900/50 border border-dashed border-slate-800 rounded-3xl text-slate-500 italic">
                  Aucun utilisateur configuré par l'administrateur.
                </div>
              )}
            </div>
          </div>
        ) : (
          <div className="max-w-md mx-auto animate-in slide-in-from-bottom-10 fade-in duration-500">
            <button 
              onClick={handleBack}
              className="mb-8 flex items-center gap-2 text-slate-500 hover:text-white transition-colors group"
            >
              <div className="p-2 bg-slate-900 rounded-xl group-hover:bg-slate-800"><ArrowLeft size={20} /></div>
              <span className="font-bold text-sm uppercase tracking-widest">Retour</span>
            </button>

            <div className={`bg-slate-900/80 backdrop-blur-xl border-2 p-8 rounded-[40px] shadow-3xl flex flex-col items-center transition-all ${error ? 'border-red-500/50 shake' : isSuccess ? 'border-green-500/50' : 'border-slate-800'}`}>
               <div className="text-center mb-8">
                  <div className={`w-20 h-20 rounded-3xl flex items-center justify-center border-2 mx-auto mb-4 ${
                    selectedUser?.role === UserRole.ADMIN ? 'bg-purple-500/10 border-purple-500/30 text-purple-400' :
                    selectedUser?.role === UserRole.BARTENDER ? 'bg-blue-500/10 border-blue-500/30 text-blue-400' :
                    'bg-emerald-500/10 border-emerald-500/30 text-emerald-400'
                  }`}>
                    <span className="text-3xl font-black">{selectedUser?.name.charAt(0).toUpperCase()}</span>
                  </div>
                  <h2 className="text-2xl font-black text-white italic">{selectedUser?.name}</h2>
                  <p className="text-[10px] text-slate-500 font-black uppercase tracking-widest mt-1">Saisissez votre code PIN</p>
               </div>

               {/* PIN Indicators */}
               <div className="flex gap-4 mb-10">
                  {[0, 1, 2, 3].map((i) => (
                    <div 
                      key={i} 
                      className={`w-4 h-4 rounded-full border-2 transition-all duration-300 ${
                        i < pin.length 
                          ? (isSuccess ? 'bg-green-500 border-green-500' : error ? 'bg-red-500 border-red-500 scale-125' : 'bg-bar-accent border-bar-accent scale-110 shadow-[0_0_15px_rgba(233,69,96,0.5)]') 
                          : 'border-slate-700'
                      }`}
                    />
                  ))}
               </div>

               {/* Numeric Pad */}
               <div className="grid grid-cols-3 gap-4 w-full">
                  {[1, 2, 3, 4, 5, 6, 7, 8, 9].map(num => (
                    <button 
                      key={num}
                      onClick={() => handleKeyPress(num.toString())}
                      disabled={isSuccess}
                      className="h-16 rounded-2xl bg-slate-950 border border-slate-800 text-white text-xl font-black hover:bg-slate-800 active:scale-90 transition-all flex items-center justify-center"
                    >
                      {num}
                    </button>
                  ))}
                  <div className="flex items-center justify-center">
                     {isSuccess ? <CheckCircle2 className="text-green-500" size={32} /> : <Lock className="text-slate-800" size={24} />}
                  </div>
                  <button 
                    onClick={() => handleKeyPress('0')}
                    disabled={isSuccess}
                    className="h-16 rounded-2xl bg-slate-950 border border-slate-800 text-white text-xl font-black hover:bg-slate-800 active:scale-90 transition-all flex items-center justify-center"
                  >
                    0
                  </button>
                  <button 
                    onClick={handleDelete}
                    disabled={isSuccess}
                    className="h-16 rounded-2xl bg-slate-800/30 text-slate-500 hover:text-white hover:bg-red-500/20 active:scale-90 transition-all flex items-center justify-center"
                  >
                    <Delete size={24} />
                  </button>
               </div>
            </div>

            <p className="text-center mt-8 text-slate-600 text-xs font-medium flex items-center justify-center gap-2">
                <ShieldCheck size={14} /> Connexion sécurisée active
            </p>
          </div>
        )}
      </div>

      <style>{`
        .shake {
          animation: shake 0.5s cubic-bezier(.36,.07,.19,.97) both;
        }
        @keyframes shake {
          10%, 90% { transform: translate3d(-1px, 0, 0); }
          20%, 80% { transform: translate3d(2px, 0, 0); }
          30%, 50%, 70% { transform: translate3d(-4px, 0, 0); }
          40%, 60% { transform: translate3d(4px, 0, 0); }
        }
      `}</style>
    </div>
  );
};

import React, { useState } from 'react';
import { User, UserRole } from '../types';
import { addUser, updateUser, deleteUser } from '../services/db';
import { UserCheck, Plus, Trash2, Edit2, ShieldCheck, User as UserIcon, X, AlertTriangle, Key } from 'lucide-react';

interface StaffPageProps {
  staff: User[];
  refreshData: () => void;
}

export const StaffPage: React.FC<StaffPageProps> = ({ staff, refreshData }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);

  const [name, setName] = useState('');
  const [role, setRole] = useState<UserRole>(UserRole.SERVER);
  const [pin, setPin] = useState('');

  const openModal = (user?: User) => {
    if (user) {
      setEditingUser(user);
      setName(user.name);
      setRole(user.role);
      setPin(user.pin || '');
    } else {
      setEditingUser(null);
      setName('');
      setRole(UserRole.SERVER);
      setPin('');
    }
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!name) return;

    if (editingUser) {
      updateUser({ ...editingUser, name, role, pin });
    } else {
      addUser({ 
        id: `u_${Date.now()}`, 
        name, 
        role, 
        pin 
      });
    }
    refreshData();
    setIsModalOpen(false);
  };

  const confirmDelete = () => {
    if (deleteConfirmId) {
      deleteUser(deleteConfirmId);
      refreshData();
      setDeleteConfirmId(null);
    }
  };

  const getRoleInfo = (role: UserRole) => {
    switch (role) {
      case UserRole.ADMIN: return { label: 'Administrateur', color: 'bg-purple-500/10 text-purple-400 border-purple-500/20', icon: <ShieldCheck size={18} /> };
      case UserRole.BARTENDER: return { label: 'Barman', color: 'bg-blue-500/10 text-blue-400 border-blue-500/20', icon: <UserIcon size={18} /> };
      default: return { label: 'Serveur', color: 'bg-emerald-500/10 text-emerald-400 border-emerald-500/20', icon: <UserIcon size={18} /> };
    }
  };

  return (
    <div className="p-4 md:p-8 h-full overflow-y-auto bg-slate-950 no-scrollbar">
      <div className="flex flex-col md:flex-row justify-between items-center mb-10 gap-4">
        <div>
          <h1 className="text-3xl font-black text-white flex items-center gap-3 italic tracking-tighter uppercase">
            <div className="p-2 bg-bar-accent/20 rounded-lg text-bar-accent">
               <UserCheck size={28} />
            </div>
            Gestion du Personnel
          </h1>
          <p className="text-slate-400 mt-1 font-medium">Configurez les comptes de vos collaborateurs et leurs accès</p>
        </div>
        <button onClick={() => openModal()} className="bg-bar-accent hover:bg-pink-600 text-white font-black py-4 px-8 rounded-2xl flex items-center gap-2 transition-all shadow-xl shadow-bar-accent/25 uppercase tracking-widest text-xs">
          <Plus size={20} /> Nouveau Collaborateur
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 pb-24 md:pb-0">
        {staff.map(user => {
          const roleInfo = getRoleInfo(user.role);
          return (
            <div key={user.id} className="bg-slate-900 border border-slate-800 rounded-3xl p-6 shadow-2xl relative group hover:border-slate-700 transition-all flex flex-col">
              <div className="flex justify-between items-start mb-6">
                 <div className={`w-14 h-14 rounded-2xl flex items-center justify-center border-2 ${roleInfo.color} shadow-lg shadow-black/20`}>
                    {roleInfo.icon}
                 </div>
                 <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                    <button onClick={() => openModal(user)} className="p-2.5 bg-slate-800 text-slate-400 hover:text-white rounded-xl transition-colors"><Edit2 size={16} /></button>
                    <button onClick={() => setDeleteConfirmId(user.id)} className="p-2.5 bg-slate-800 text-slate-400 hover:text-red-500 rounded-xl transition-colors"><Trash2 size={16} /></button>
                 </div>
              </div>

              <div className="mb-6">
                 <h3 className="text-xl font-black text-white truncate italic">{user.name}</h3>
                 <span className={`inline-flex items-center gap-1.5 mt-2 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest border ${roleInfo.color}`}>
                    {roleInfo.label}
                 </span>
              </div>

              <div className="mt-auto pt-6 border-t border-slate-800/50 flex items-center justify-between text-slate-500">
                  <div className="flex items-center gap-2 text-[11px] font-black uppercase tracking-wider text-slate-300">
                     <Key size={14} className="text-bar-accent" />
                     <span className="text-slate-500 mr-1">Code:</span>
                     <span className="bg-slate-950 px-2 py-0.5 rounded border border-slate-800 font-mono text-bar-accent tracking-widest shadow-inner">
                        {user.pin || '----'}
                     </span>
                  </div>
                  <div className="text-[10px] font-black uppercase opacity-40">ID:{user.id.slice(-4)}</div>
              </div>
            </div>
          );
        })}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-[70] flex items-center justify-center bg-black/95 backdrop-blur-md p-4 animate-in fade-in duration-200">
          <div className="bg-slate-900 border border-slate-800 w-full max-w-md rounded-3xl shadow-2xl p-8 relative animate-in zoom-in duration-300">
            <button onClick={() => setIsModalOpen(false)} className="absolute top-6 right-6 text-slate-400 hover:text-white bg-slate-800 p-1 rounded-full"><X size={24} /></button>
            <h2 className="text-2xl font-black text-white mb-8 italic flex items-center gap-3">
                {editingUser ? <Edit2 className="text-bar-accent" /> : <Plus className="text-bar-accent" />}
                {editingUser ? 'MODIFIER PROFIL' : 'NOUVEAU COMPTE'}
            </h2>
            <form onSubmit={handleSubmit} className="space-y-6">
              <div>
                <label className="block text-slate-500 text-[10px] font-black uppercase tracking-[0.2em] mb-2">Nom du collaborateur</label>
                <input type="text" required value={name} onChange={e => setName(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-2xl p-4 text-white focus:ring-2 focus:ring-bar-accent outline-none font-bold" placeholder="Ex: Lucas B." autoFocus />
              </div>
              <div>
                <label className="block text-slate-500 text-[10px] font-black uppercase tracking-[0.2em] mb-2">Rôle & Permissions</label>
                <select value={role} onChange={e => setRole(e.target.value as UserRole)} className="w-full bg-slate-950 border border-slate-800 rounded-2xl p-4 text-white focus:ring-2 focus:ring-bar-accent outline-none font-bold appearance-none">
                    <option value={UserRole.ADMIN}>Administrateur (Tout accès)</option>
                    <option value={UserRole.BARTENDER}>Barman (Caisse, Cuisine, Stocks)</option>
                    <option value={UserRole.SERVER}>Serveur (Caisse, Tables)</option>
                </select>
              </div>
              <div>
                <label className="block text-slate-500 text-[10px] font-black uppercase tracking-[0.2em] mb-2">Code PIN (4 chiffres)</label>
                <input type="password" value={pin} onChange={e => setPin(e.target.value)} className="w-full bg-slate-950 border border-slate-800 rounded-2xl p-4 text-white focus:ring-2 focus:ring-bar-accent outline-none font-mono tracking-widest text-lg" placeholder="••••" maxLength={4} />
              </div>
              <div className="flex gap-4 pt-4">
                 <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 py-4 text-slate-400 font-black uppercase text-xs tracking-widest hover:text-white transition-colors">Annuler</button>
                 <button type="submit" className="flex-1 py-4 bg-bar-accent hover:bg-pink-600 text-white font-black uppercase text-xs tracking-widest rounded-2xl shadow-xl shadow-bar-accent/20 transition-all">
                    {editingUser ? 'Sauvegarder' : 'Créer le compte'}
                 </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {deleteConfirmId && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/98 backdrop-blur-lg p-4 animate-in fade-in duration-200">
