};

import React, { useState, useEffect } from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { Navbar } from './components/Navbar';
import { POS } from './pages/POS';
import { Kitchen } from './pages/Kitchen';
import { Dashboard } from './pages/Dashboard';
import { ReportsPage } from './pages/ReportsPage';
import { Products } from './pages/Products';
import { CategoriesPage } from './pages/CategoriesPage';
import { SettingsPage } from './pages/SettingsPage';
import { TablesPage } from './pages/TablesPage'; 
import { ClientsPage } from './pages/ClientsPage';
import { SalesHistoryPage } from './pages/SalesHistoryPage';
import { StaffPage } from './pages/StaffPage';
import { LoginPage } from './pages/LoginPage';
import { CartItem, Product, Order, OrderStatus, CategoryDef, TableDef, Client, User, UserRole, TableStatus } from './types';
import { initDB, getProducts, getOrders, insertOrder, updateOrderStatusInDB, getCategories, getTables, getClients, getSetting, saveSetting, getUsers } from './services/db';
import { Loader2, AlertTriangle, RefreshCw } from 'lucide-react';

const generateId = () => Math.random().toString(36).substr(2, 9);

const App: React.FC = () => {
  const [isDbReady, setIsDbReady] = useState(false);
  const [dbError, setDbError] = useState<string | null>(null);
  const [currentUser, setCurrentUser] = useState<User | null>(null);

  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]);
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<CategoryDef[]>([]);
  const [tables, setTables] = useState<TableDef[]>([]);
  const [clients, setClients] = useState<Client[]>([]);
  const [staff, setStaff] = useState<User[]>([]);
  const [currency, setCurrency] = useState('FCFA');

  useEffect(() => {
    const setup = async () => {
      try {
        await initDB();
        refreshData();

        const savedUser = localStorage.getItem('barflow_session');
        if (savedUser) {
          setCurrentUser(JSON.parse(savedUser));
        }

        setIsDbReady(true);
      } catch (e) {
        console.error("Failed to init DB", e);
        setDbError("Impossible de charger la base de données SQLite.");
      }
    };
    setup();
  }, []);

  const refreshData = () => {
     setProducts(getProducts());
     setOrders(getOrders());
     setCategories(getCategories());
     setTables(getTables());
     setClients(getClients());
     setStaff(getUsers());
     setCurrency(getSetting('currency', 'FCFA'));
  };

  const handleLogin = (user: User) => {
    setCurrentUser(user);
    localStorage.setItem('barflow_session', JSON.stringify(user));
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('barflow_session');
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const updateCartItemQuantity = (productId: string, newQuantity: number) => {
    if (newQuantity <= 0) {
      removeFromCart(productId);
      return;
    }
    setCart(prev => prev.map(item => 
      item.id === productId ? { ...item, quantity: newQuantity } : item
    ));
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  };

  const clearCart = () => setCart([]);

  const placeOrder = (tableName: string, client?: Client | null) => {
    if (cart.length === 0) return;

    const tableNumber = parseInt(tableName);
    const newOrder: Order = {
      id: generateId(),
      items: [...cart],
      total: cart.reduce((sum, item) => sum + (item.price * item.quantity), 0),
      status: OrderStatus.PENDING,
      timestamp: Date.now(),
      tableNumber: isNaN(tableNumber) ? undefined : tableNumber,
      tableName: tableName,
      clientId: client?.id,
      clientName: client?.name
    };
    insertOrder(newOrder);
    refreshData();
    clearCart();
  };

  const updateOrderStatus = (orderId: string, status: OrderStatus) => {
    updateOrderStatusInDB(orderId, status);
    refreshData();
  };

  const ProtectedRoute = ({ children, roles }: React.PropsWithChildren<{ roles: UserRole[] }>) => {
    if (!currentUser) return <Navigate to="/login" />;
    if (!roles.includes(currentUser.role)) return <Navigate to="/" />;
    return <>{children}</>;
  };

  if (dbError) {
    return (
      <div className="h-screen w-screen bg-slate-950 flex flex-col items-center justify-center text-white p-6 text-center">
        <AlertTriangle className="text-red-500 mb-4" size={64} />
        <h1 className="text-2xl font-bold mb-2">Erreur</h1>
        <button onClick={() => window.location.reload()} className="px-6 py-3 bg-slate-800 rounded-xl font-bold flex items-center gap-2"><RefreshCw size={20} /> Réessayer</button>
      </div>
    );
  }

  if (!isDbReady) {
    return (
      <div className="h-screen w-screen bg-slate-950 flex flex-col items-center justify-center text-white">
        <Loader2 className="animate-spin mb-4 text-bar-accent" size={48} />
        <p>Initialisation...</p>
      </div>
    );
  }

  return (
    <Router>
      <div className="flex h-screen bg-slate-950 text-slate-200 font-sans overflow-hidden">
        {currentUser && <Navbar currentUser={currentUser} onLogout={handleLogout} />}
        <main className={`flex-1 h-full overflow-hidden relative transition-all duration-300 ${currentUser ? 'md:ml-20 lg:ml-64' : ''}`}>
          <Routes>
            <Route path="/login" element={!currentUser ? <LoginPage onLogin={handleLogin} users={staff} /> : <Navigate to="/" />} />

            <Route 
              path="/" 
              element={
                <ProtectedRoute roles={[UserRole.ADMIN, UserRole.BARTENDER, UserRole.SERVER]}>
                  <Dashboard orders={orders} products={products} currency={currency} />
                </ProtectedRoute>
              } 
            />

            <Route 
              path="/pos" 
              element={
                <ProtectedRoute roles={[UserRole.ADMIN, UserRole.BARTENDER, UserRole.SERVER]}>
                  <POS 
                    products={products}
                    categories={categories}
                    tables={tables}
                    activeOrders={orders}
                    clients={clients}
                    cart={cart} 
                    addToCart={addToCart}
                    updateCartItemQuantity={updateCartItemQuantity}
                    removeFromCart={removeFromCart} 
                    clearCart={clearCart}
                    placeOrder={placeOrder}
                    currency={currency}
                  />
                </ProtectedRoute>
              } 
            />

            <Route 
              path="/kitchen" 
              element={
                <ProtectedRoute roles={[UserRole.ADMIN, UserRole.BARTENDER]}>
                  <Kitchen orders={orders} updateOrderStatus={updateOrderStatus} clients={clients} />
                </ProtectedRoute>
              } 
            />

            <Route 
              path="/reports" 
              element={
                <ProtectedRoute roles={[UserRole.ADMIN]}>
                  <ReportsPage orders={orders} products={products} currency={currency} />
                </ProtectedRoute>
              } 
            />

            <Route 
              path="/history" 
              element={
                <ProtectedRoute roles={[UserRole.ADMIN, UserRole.BARTENDER, UserRole.SERVER]}>
                  <SalesHistoryPage orders={orders} currency={currency} />
                </ProtectedRoute>
              } 
            />

            <Route 
              path="/clients" 
              element={
                <ProtectedRoute roles={[UserRole.ADMIN, UserRole.SERVER]}>
                  <ClientsPage clients={clients} refreshData={refreshData} currency={currency} orders={orders} />
                </ProtectedRoute>
              } 
            />

            <Route 
              path="/staff" 
              element={
                <ProtectedRoute roles={[UserRole.ADMIN]}>
                  <StaffPage staff={staff} refreshData={refreshData} />
                </ProtectedRoute>
              } 
            />

            <Route 
              path="/products" 
              element={
                <ProtectedRoute roles={[UserRole.ADMIN, UserRole.BARTENDER]}>
                  <Products products={products} categories={categories} refreshData={refreshData} currency={currency} />
                </ProtectedRoute>
              } 
            />

            <Route 
              path="/tables" 
              element={
                <ProtectedRoute roles={[UserRole.ADMIN, UserRole.SERVER]}>
                  <TablesPage tables={tables} refreshData={refreshData} orders={orders} currency={currency} />
                </ProtectedRoute>
              } 
            />

            <Route 
              path="/categories" 
              element={
                <ProtectedRoute roles={[UserRole.ADMIN]}>
                  <CategoriesPage categories={categories} refreshData={refreshData} />
                </ProtectedRoute>
              } 
            />

            <Route 
              path="/settings" 
              element={
                <ProtectedRoute roles={[UserRole.ADMIN]}>
                  <SettingsPage currentCurrency={currency} onCurrencyChange={(s) => { saveSetting('currency', s); setCurrency(s); }} />
                </ProtectedRoute>
              } 
            />

            <Route path="*" element={currentUser ? <Navigate to="/" /> : <Navigate to="/login" />} />
          </Routes>
        </main>
      </div>
    </Router>
  );
};

export default App;

import { Product, Order, OrderStatus, CartItem, CategoryDef, Category, TableDef, TableStatus, Client, PaymentMethod, StockEntry, User, UserRole } from '../types';
import { INITIAL_MENU } from '../constants';

let db: any = null;
const DB_STORAGE_KEY = 'barflow_sqlite_db_v1';

export const initDB = async () => {
  if (db) return;

  if (typeof (window as any).initSqlJs !== 'function') {
      throw new Error("sql.js library not loaded properly.");
  }

  const SQL = await (window as any).initSqlJs({
    locateFile: (file: string) => `https://cdnjs.cloudflare.com/ajax/libs/sql.js/1.8.0/${file}`
  });

  const savedDb = localStorage.getItem(DB_STORAGE_KEY);

  if (savedDb) {
    try {
        const binaryString = atob(savedDb);
        const bytes = new Uint8Array(binaryString.length);
        for (let i = 0; i < binaryString.length; i++) {
        bytes[i] = binaryString.charCodeAt(i);
        }
        db = new SQL.Database(bytes);
    } catch (e) {
        db = new SQL.Database();
    }
  } else {
    db = new SQL.Database();
  }

  createTables();
  applyMigrations(); 

  if (!savedDb) {
      seedData();
      saveDB();
  }
};

const saveDB = () => {
  if (!db) return;
  const data = db.export();
  let binaryString = '';
  for (let i = 0; i < data.length; i++) {
    binaryString += String.fromCharCode(data[i]);
  }
  localStorage.setItem(DB_STORAGE_KEY, btoa(binaryString));
};

const createTables = () => {
  db.run(`CREATE TABLE IF NOT EXISTS categories (id TEXT PRIMARY KEY, name TEXT, icon TEXT);`);
  db.run(`CREATE TABLE IF NOT EXISTS products (
    id TEXT PRIMARY KEY, name TEXT, price REAL, cost_price REAL DEFAULT 0, 
    stock INTEGER DEFAULT 0, alert_threshold INTEGER DEFAULT 5, 
    category TEXT, image TEXT, description TEXT, is_available INTEGER DEFAULT 1
  );`);
  db.run(`CREATE TABLE IF NOT EXISTS orders (id TEXT PRIMARY KEY, total REAL, status TEXT, timestamp INTEGER, table_number INTEGER, table_name TEXT, client_id TEXT, client_name TEXT, payment_method TEXT);`);
  db.run(`CREATE TABLE IF NOT EXISTS order_items (id INTEGER PRIMARY KEY AUTOINCREMENT, order_id TEXT, name TEXT, price REAL, cost_price REAL DEFAULT 0, quantity INTEGER, FOREIGN KEY(order_id) REFERENCES orders(id));`);
  db.run(`CREATE TABLE IF NOT EXISTS tables (id TEXT PRIMARY KEY, name TEXT, zone TEXT, status TEXT DEFAULT 'FREE', reservation_note TEXT);`);
  db.run(`CREATE TABLE IF NOT EXISTS clients (id TEXT PRIMARY KEY, name TEXT, phone TEXT, email TEXT, notes TEXT, loyalty_points INTEGER DEFAULT 0, total_spent REAL DEFAULT 0, balance REAL DEFAULT 0, last_visit INTEGER);`);
  db.run(`CREATE TABLE IF NOT EXISTS users (id TEXT PRIMARY KEY, name TEXT, role TEXT, pin TEXT);`);
  db.run(`CREATE TABLE IF NOT EXISTS settings (key TEXT PRIMARY KEY, value TEXT);`);
  db.run(`CREATE TABLE IF NOT EXISTS stock_history (id INTEGER PRIMARY KEY AUTOINCREMENT, product_id TEXT, quantity INTEGER, timestamp INTEGER, note TEXT);`);
};

const applyMigrations = () => {
    try { db.run("ALTER TABLE products ADD COLUMN cost_price REAL DEFAULT 0"); } catch (e) {}
    try { db.run("ALTER TABLE order_items ADD COLUMN cost_price REAL DEFAULT 0"); } catch (e) {}
    try { db.run("ALTER TABLE tables ADD COLUMN status TEXT DEFAULT 'FREE'"); } catch (e) {}
    try { db.run("ALTER TABLE tables ADD COLUMN reservation_note TEXT"); } catch (e) {}
    try { db.run("CREATE TABLE IF NOT EXISTS users (id TEXT PRIMARY KEY, name TEXT, role TEXT, pin TEXT);"); } catch (e) {}

    // Auto-fix table status based on orders
    db.run(`UPDATE tables SET status = 'OCCUPIED' WHERE name IN (SELECT table_name FROM orders WHERE status != 'Payé')`);
};

const seedData = () => {
  const catStmt = db.prepare("INSERT INTO categories VALUES (?, ?, ?)");
  const defaultCats = [
    { id: 'cat_1', name: Category.COCKTAIL, icon: 'Martini' },
    { id: 'cat_2', name: Category.BEER, icon: 'Beer' },
    { id: 'cat_3', name: Category.WINE, icon: 'Wine' },
    { id: 'cat_4', name: Category.SOFT, icon: 'GlassWater' },
    { id: 'cat_5', name: Category.FOOD, icon: 'Utensils' },
  ];
  defaultCats.forEach(c => catStmt.run([c.id, c.name, c.icon]));
  catStmt.free();

  const stmt = db.prepare("INSERT INTO products (id, name, price, cost_price, stock, alert_threshold, category, image, description, is_available) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)");
  INITIAL_MENU.forEach(p => {
    stmt.run([p.id, p.name, p.price, p.price * 0.3, 50, 10, p.category, p.image, p.description || '', 1]);
  });
  stmt.free();

  const tableStmt = db.prepare("INSERT INTO tables (id, name, zone, status) VALUES (?, ?, ?, ?)");
  const defaultTables = [
    { id: 't1', name: 'S1', zone: 'Salle', status: 'FREE' },
    { id: 't2', name: 'S2', zone: 'Salle', status: 'FREE' },
    { id: 't10', name: 'T1', zone: 'Terrasse', status: 'FREE' },
    { id: 't20', name: 'Bar 1', zone: 'Bar', status: 'FREE' },
    { id: 't30', name: 'VIP A', zone: 'VIP', status: 'FREE' },
  ];
  defaultTables.forEach(t => tableStmt.run([t.id, t.name, t.zone, t.status]));
  tableStmt.free();

  // Seed Users
  const userStmt = db.prepare("INSERT INTO users (id, name, role, pin) VALUES (?, ?, ?, ?)");
  const defaultUsers = [
    { id: 'u1', name: 'Direction', role: UserRole.ADMIN, pin: '0000' },
    { id: 'u2', name: 'Barman', role: UserRole.BARTENDER, pin: '1234' },
    { id: 'u3', name: 'Serveur', role: UserRole.SERVER, pin: '5678' },
  ];
  defaultUsers.forEach(u => userStmt.run([u.id, u.name, u.role, u.pin]));
  userStmt.free();

  db.run("INSERT INTO settings (key, value) VALUES (?, ?)", ['currency', 'FCFA']);
};

export const getUsers = (): User[] => {
  if (!db) return [];
  try {
    const stmt = db.prepare("SELECT * FROM users");
    const users: User[] = [];
    while (stmt.step()) {
      const row = stmt.getAsObject();
      users.push({ id: row.id, name: row.name, role: row.role as UserRole, pin: row.pin });
    }
    stmt.free();
    return users;
  } catch (e) { return []; }
};

export const addUser = (user: User) => {
  if (!db) return;
  db.run("INSERT INTO users (id, name, role, pin) VALUES (?, ?, ?, ?)", [user.id, user.name, user.role, user.pin || '']);
  saveDB();
};

export const updateUser = (user: User) => {
  if (!db) return;
  db.run("UPDATE users SET name = ?, role = ?, pin = ? WHERE id = ?", [user.name, user.role, user.pin || '', user.id]);
  saveDB();
};

